INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ak_alaska-gdl-restrictions-daily-life_0', 'quiz_ak_alaska-gdl-restrictions-daily-life', 'During which hours are Alaska provisional license holders generally prohibited from driving?', '["10:00 p.m. to 5:00 a.m.","11:00 p.m. to 6:00 a.m.","1:00 a.m. to 5:00 a.m.","Midnight to 6:00 a.m."]', 2, 'Alaska''s GDL nighttime restriction runs from 1:00 a.m. to 5:00 a.m., with exceptions for work, school activities, emergencies, or when supervised by a licensed adult 21 or older.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ak_alaska-gdl-restrictions-daily-life_1', 'quiz_ak_alaska-gdl-restrictions-daily-life', 'For how long after receiving a provisional license must a teen avoid carrying non-family passengers under 21?', '["30 days","3 months","6 months","1 year"]', 2, 'The passenger restriction lasts six months. Immediate family members are exempt, as are trips supervised by a licensed driver 21 or older in the front seat.', 1
