INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ak_alaska-specific-driving-quirks_0', 'quiz_ak_alaska-specific-driving-quirks', 'If a collision with a moose is unavoidable, what is the recommended action?', '["Swerve hard into the opposing lane","Accelerate to push through the impact","Brake firmly without swerving into oncoming traffic or off the shoulder","Honk and maintain speed"]', 2, 'Swerving typically causes more severe crashes than the moose strike itself. Brake hard, stay in your lane, and reduce impact speed as much as possible.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ak_alaska-specific-driving-quirks_1', 'quiz_ak_alaska-specific-driving-quirks', 'Which Alaska resource provides up-to-date road conditions, closures, and weather information?', '["Call 911","511 Alaska (5-1-1 or 511.alaska.gov)","The Alaska DMV main line","The National Weather Service only"]', 1, '511 Alaska is the state''s official traveler information service for road conditions, closures, and construction.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ak_alaska-specific-driving-quirks_2', 'quiz_ak_alaska-specific-driving-quirks', 'What is true about studded tires in Alaska?', '["They are required statewide year-round","They are legal during the posted winter season but illegal in summer","They are illegal everywhere in Alaska","They may only be used north of the Arctic Circle"]', 1, 'Studded tires are permitted during winter months (dates vary by region) but may not be used in summer; doing so is a citable violation.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ak_alaska-specific-driving-quirks_3', 'quiz_ak_alaska-specific-driving-quirks', 'Why is winter driving in Alaska especially dangerous beyond the cold?', '["Most roads close completely in winter","Black ice, long darkness, and remote distances multiply risk","Studded tires are banned in winter","GDL restrictions are suspended in winter"]', 1, 'Black ice is often invisible, winter daylight is extremely short, and breakdowns between towns can become survival situations — all reasons to slow down and prepare.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ak_alaska-specific-driving-quirks_4', 'quiz_ak_alaska-specific-driving-quirks', 'What is a smart habit when driving Alaska''s gravel highways such as the Dalton?', '["Drive in the center of the road to avoid the shoulder","Keep headlights off to save battery","Slow down and move right for oncoming traffic, keep headlights on, and fuel up at every opportunity","Always drive at the posted maximum speed regardless of conditions"]', 2, 'Slowing for oncoming traffic reduces rock strikes, headlights are legally required on the Dalton, and fuel stops can be more than 200 miles apart.', 4
);

