INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_getting-your-alabama-learner-license_2', 'quiz_al_getting-your-alabama-learner-license', 'While holding only a Learner License in Alabama, who must be seated beside the teen driver?', '["Any licensed driver age 18 or older","A licensed driver age 21 or older (or licensed parent/guardian/spouse/instructor)","Only a parent or legal guardian","Another teen with a full license"]', 1, 'Alabama requires a licensed driver age 21 or older - or a licensed parent, guardian, spouse, or certified driver education instructor - in the front passenger seat at all times while a learner is driving.', 2
