INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-gdl-restrictions-daily-life_1', 'quiz_al_alabama-gdl-restrictions-daily-life', 'How many non-family passengers under age 21 may a Stage I Restricted License holder transport without a supervising adult?', '["Zero","One","Two","Three"]', 1, 'A Stage I driver may carry no more than one non-family passenger under 21 unless a parent, guardian, or licensed driver 21 or older is in the vehicle.', 1
