INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-gdl-restrictions-daily-life_2', 'quiz_al_alabama-gdl-restrictions-daily-life', 'Which of the following is a valid exception to Alabama''s nighttime driving restriction for Stage I drivers?', '["Driving home from a friend''s house","Driving to or from work with proof of employment","Driving to pick up food","Driving to a party"]', 1, 'Driving to or from a job is one of the explicit exceptions, provided the teen can show proof of employment such as a pay stub or letter from the employer.', 2
