INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-gdl-restrictions-daily-life_3', 'quiz_al_alabama-gdl-restrictions-daily-life', 'What is Alabama''s cell phone rule for drivers under 18 holding a restricted license?', '["Hands-free calls are allowed","Texting only is prohibited","All handheld communication device use is prohibited","There is no specific rule for teens"]', 2, 'Alabama prohibits any use of a handheld communication device by drivers under 18 with a restricted license. Texting is also banned for every driver in the state regardless of age.', 3
