INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-gdl-restrictions-daily-life_4', 'quiz_al_alabama-gdl-restrictions-daily-life', 'Which of the following passengers would NOT count toward the Stage I one-passenger limit?', '["A 17-year-old classmate","A 19-year-old friend from a different school","A 14-year-old sibling who lives in your home","A 20-year-old cousin who lives in a different city"]', 2, 'Family members living in the driver''s household, such as siblings, do not count toward the non-family passenger limit. Friends and non-household relatives under 21 do count.', 4
