INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-rules-and-quirks_0', 'quiz_al_alabama-rules-and-quirks', 'Under Alabama''s Move Over Law, if you cannot safely change lanes when passing a stopped emergency vehicle, what must you do?', '["Maintain the posted speed limit","Slow to at least 15 mph below the posted speed limit","Stop completely until the emergency vehicle leaves","Honk to alert the emergency personnel"]', 1, 'Alabama''s Move Over Law requires drivers who cannot safely change lanes to slow to at least 15 mph below the posted speed limit (or 25 mph if the limit is 25 or less).', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-rules-and-quirks_1', 'quiz_al_alabama-rules-and-quirks', 'What is the maximum legal blood-alcohol concentration (BAC) for a driver under age 21 in Alabama?', '["0.00%","0.02%","0.05%","0.08%"]', 1, 'Alabama enforces a 0.02% BAC limit for drivers under 21 - effectively a zero-tolerance standard. The adult limit is 0.08%.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-rules-and-quirks_2', 'quiz_al_alabama-rules-and-quirks', 'On a two-lane road, what must you do when a school bus stops with its red lights flashing and stop arm extended?', '["Only traffic behind the bus must stop","Slow to 20 mph and pass carefully","All traffic in both directions must stop","Stop only if children are visible"]', 2, 'On any two-lane road, all traffic in both directions must stop for a school bus displaying flashing red lights and an extended stop arm. The rule changes only on divided highways with a physical median.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-rules-and-quirks_3', 'quiz_al_alabama-rules-and-quirks', 'Alabama law requires headlights to be turned on under which of the following conditions?', '["Only between sunset and sunrise","Anytime the windshield wipers are in continuous use due to weather","Only when visibility is less than 100 feet","Only on interstate highways"]', 1, 'Alabama requires headlights (not just daytime running lights) any time the windshield wipers are in continuous use due to weather, so other drivers can see your vehicle''s tail lights.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_al_alabama-rules-and-quirks_4', 'quiz_al_alabama-rules-and-quirks', 'If a deer suddenly steps in front of your car on an Alabama back road, what is the safest action?', '["Swerve hard into the opposite lane","Brake straight and stay in your lane","Accelerate through to pass it quickly","Swerve onto the shoulder and brake"]', 1, 'Brake straight and stay in your lane. Most fatal animal-collision crashes occur when drivers swerve and lose control, leaving the road or hitting another vehicle. Hitting the deer at reduced speed is typically far safer.', 4
);

