INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_getting-your-arkansas-learners-license_1', 'quiz_ar_getting-your-arkansas-learners-license', 'Who must accompany an Arkansas Learner''s License holder while driving?', '["Any licensed driver age 18 or older","A parent or legal guardian only","A licensed driver age 21 or older seated in the front passenger seat","An instructor from a state-approved driving school"]', 2, 'Arkansas requires a licensed driver who is at least 21 years old to be seated in the front passenger seat at all times while a Learner''s License holder is driving.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_getting-your-arkansas-learners-license_2', 'quiz_ar_getting-your-arkansas-learners-license', 'How long must you hold an Arkansas Learner''s License before advancing to an Intermediate License?', '["30 days","90 days","6 months with a clean driving record","12 months regardless of driving record"]', 2, 'Arkansas requires at least 6 months at the Learner''s stage with a clean driving record. A serious traffic conviction can reset the clock.', 2
