INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_arkansas-gdl-restrictions-in-daily-life_1', 'quiz_ar_arkansas-gdl-restrictions-in-daily-life', 'Which of the following is a valid exception to the Arkansas Intermediate License nighttime curfew?', '["Driving home from a friend''s birthday party","Driving to or from a school-sanctioned activity","Driving to pick up food after a movie","Driving anywhere as long as you have your phone with you"]', 1, 'Travel to or from work, school, or a school-sanctioned activity is a recognized exception. Social outings are not.', 1
