INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_arkansas-gdl-restrictions-in-daily-life_2', 'quiz_ar_arkansas-gdl-restrictions-in-daily-life', 'How many unrelated passengers under 21 may an Arkansas Intermediate License holder transport without a 21+ adult in the car?', '["Zero","One","Three","Unlimited as long as everyone is belted"]', 1, 'Intermediate License holders may not transport more than one passenger under 21 who is not an immediate family member, unless a licensed driver 21 or older is also in the vehicle.', 2
