INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_arkansas-gdl-restrictions-in-daily-life_3', 'quiz_ar_arkansas-gdl-restrictions-in-daily-life', 'Under Arkansas law, may a 17-year-old driver use a hands-free Bluetooth headset to take a phone call while driving?', '["Yes, hands-free is always allowed","Yes, but only on highways","No, drivers under 18 may not use a wireless phone at all while driving","Only if the call lasts less than 60 seconds"]', 2, 'Arkansas prohibits drivers under 18 from using any wireless telephone - handheld or hands-free - while driving. Drivers 18-20 may use a hands-free device, and texting is banned for everyone.', 3
