INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_arkansas-gdl-restrictions-in-daily-life_4', 'quiz_ar_arkansas-gdl-restrictions-in-daily-life', 'What can happen if an Arkansas Intermediate License holder receives a serious moving violation?', '["Nothing - GDL violations are not reported","It may reset the clean-record clock and delay advancement to a full license","The license is automatically revoked for life","Only the parents are fined; the teen faces no consequences"]', 1, 'A serious violation can reset the 6-month clean-record requirement, delay advancement to a Class D license, and trigger parental notification or suspension depending on points.', 4
