INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_arkansas-specific-rules-and-quirks_2', 'quiz_ar_arkansas-specific-rules-and-quirks', 'What is the consequence in Arkansas of refusing a breath, blood, or urine test under the implied consent law for a first offense?', '["A warning only","A $25 fine","Automatic 6-month license suspension, separate from any DUI charge","No consequence if you later pass a private test"]', 2, 'Refusing chemical testing triggers an automatic 6-month license suspension for a first refusal in Arkansas, in addition to any DUI penalties.', 2
