INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ar_arkansas-specific-rules-and-quirks_4', 'quiz_ar_arkansas-specific-rules-and-quirks', 'You are driving on a rural Arkansas road and encounter standing water across the pavement after a heavy rain. What is the safest action?', '["Speed up to create a wake and push through","Drive through slowly in low gear","Turn around and find another route - never drive through standing water","Roll down the windows in case the engine stalls"]', 2, 'Arkansas DOT messaging is ''Turn around, don''t drown.'' As little as 12 inches of moving water can sweep away a small car, and flash flooding is a leading cause of weather-related driving deaths in the state.', 4
