INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_az_teen_1_0_0', 'rp_az_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Class G Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":30,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-AZ","minPermitAge":15.5,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Arizona Department of Transportation, Motor Vehicle Division (ADOT MVD)","minPermitAge":15.5,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"For the first 6 months after a Class G graduated license is issued, the driver may not drive between midnight (12:00 a.m.) and 5:00 a.m. unless accompanied by a parent or legal guardian, traveling to or from work, school, or a religious activity, or driving in response to an emergency.","passengerRestriction":"For the first 6 months of a Class G graduated license, the driver may not transport more than one passenger under age 18 who is not an immediate family member, unless accompanied by a parent or legal guardian in the front seat.","cellPhoneRule":"Arizona prohibits all drivers from holding or supporting a cell phone or other handheld wireless device while driving (hands-free required statewide). In addition, drivers under 18 with a Class G graduated license or an instruction permit may not use any wireless communication device while driving for the first 6 months after license issuance, except in an emergency.","notes":"Arizona''s Graduated Driver License (GDL) program applies to drivers under 18. Teens must hold an Instruction Permit for at least 6 months and complete 30 hours of supervised driving (10 of which must be at night) before applying for a Class G license at age 16. A parent/guardian must certify the practice hours on Form 40-5122. Driver education from a state-licensed school can substitute for some on-road practice requirements, but the 6-month permit holding period still applies. Arizona does not currently require a state-mandated minimum number of classroom hours for licensure, but most approved teen driver education programs follow the 30/6 (classroom/BTW) industry standard. The Class G license remains in effect until age 18, when it converts to a standard Class D operator license.","needsReview":["Exact required classroom hours (Arizona does not statutorily mandate 30 classroom hours for licensure; 30 is a common program standard, not a state minimum)","Whether 6 BTW hours is the Arizona-approved teen driver education minimum or a program convention","Current statutory citation for the hands-free cell phone law (ARS 28-914) and any 2024-2026 amendments","Whether ADOT MVD now accepts electronic submission of the parental certification (Form 40-5122) rather than manual paper submission","Whether the nighttime curfew window is 12:00 a.m.-5:00 a.m. or has been amended"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
