INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_az_az-gdl-restrictions-daily-life_2', 'quiz_az_az-gdl-restrictions-daily-life', 'Which of the following is NOT a valid exception to Arizona''s teen nighttime curfew?', '["Driving home from a paid job","Driving with a parent or legal guardian in the car","Driving home from a friend''s house after watching a movie","Driving to a school-sanctioned activity"]', 2, 'Driving home from a friend''s house for a social activity is not an exception. The recognized exceptions are work, school, religious activities, emergencies, and driving with a parent or guardian.', 2
