INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_az_az-gdl-restrictions-daily-life_3', 'quiz_az_az-gdl-restrictions-daily-life', 'Which statement about Arizona''s cell phone rules is correct?', '["Only drivers under 18 have any phone restrictions","All drivers must use hands-free; teens in their first 6 months may not use any wireless device except in an emergency","Texting is allowed at red lights","Bluetooth use is unrestricted for everyone"]', 1, 'Arizona is a hands-free state for all drivers. Teens with a permit or in the first 6 months of a Class G license face a stricter rule: no wireless device use at all (even hands-free) except in an emergency.', 3
