INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_az_az-specific-road-rules-and-quirks_1', 'quiz_az_az-specific-road-rules-and-quirks', 'ADOT''s official guidance when caught in a dust storm (haboob) is "Pull Aside, Stay Alive." After pulling completely off the road, what should you do with your vehicle''s lights?', '["Turn on hazard lights so other drivers can see you","Leave headlights on dim","Turn off all lights, including hazards, and take your foot off the brake","Flash high beams until the storm passes"]', 2, 'Turn all lights off — including hazards — and take your foot off the brake. Other drivers sometimes follow taillights through dust, mistakenly thinking they are still on the road, which causes pileups.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_az_az-specific-road-rules-and-quirks_2', 'quiz_az_az-specific-road-rules-and-quirks', 'What is the standard speed limit in an active Arizona school zone?', '["25 mph","20 mph","15 mph","10 mph"]', 2, 'Arizona school zones are typically 15 mph when children are present — one of the lowest school zone speed limits in the United States.', 2
