INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_az_az-specific-road-rules-and-quirks_3', 'quiz_az_az-specific-road-rules-and-quirks', 'On a divided highway with a physical median, what must drivers traveling in the opposite direction from a stopped school bus with flashing red lights do?', '["Stop completely until the bus moves","They are not required to stop because of the physical median","Slow to 15 mph and pass with caution","Pull onto the shoulder and wait"]', 1, 'On a divided highway with a physical median, only drivers traveling behind the bus must stop. The physical median separates oncoming traffic from the bus''s loading zone.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_az_az-specific-road-rules-and-quirks_4', 'quiz_az_az-specific-road-rules-and-quirks', 'Arizona''s Move Over Law requires you to do what when approaching a stopped emergency vehicle, tow truck, or maintenance vehicle with flashing lights?', '["Move one lane away from the vehicle if safe, or significantly slow down if you cannot","Stop completely until waved past","Honk to alert the workers","Nothing extra is required if you maintain the speed limit"]', 0, 'Arizona''s Move Over Law requires drivers to move one lane away from stopped emergency, tow, and maintenance vehicles with flashing lights. If you cannot safely change lanes, slow down significantly as you pass.', 4
);

