  'rpv_co_teen_1_0_0', 'rp_co_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Colorado Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-CO","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Colorado Department of Revenue, Division of Motor Vehicles (DMV)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":12,"nighttimeRestriction":"No driving between midnight and 5:00 a.m. during the first year of licensure unless accompanied by a parent/guardian/licensed driving instructor, or driving to/from work, school, or a medical emergency.","passengerRestriction":"During the first 6 months of licensure: no passengers under 21 unless a parent/guardian or licensed driver 21+ is in the front seat. During months 7-12: only one passenger under 21 allowed (siblings and supervised situations excepted).","cellPhoneRule":"Drivers under 18 are prohibited from using any wireless/cell phone while driving, including hands-free, except to report an emergency.","notes":"Colorado has a tiered Graduated Driver Licensing (GDL) program administered by the Colorado DMV. Teens 15 to 15.5 must complete a 30-hour state-approved driver education course before obtaining an instruction permit; teens 15.5 to 16 may take a 4-hour Driver Awareness Program (DAP) in lieu of the full course if no driver ed is locally available; teens 16 to 21 may take the written test without driver ed but still need permit-holding time. Required behind-the-wheel training is 6 hours with a state-approved school. Permit must be held for at least 12 months before a license can be issued, and the teen must log 50 hours of supervised driving (10 of which must be at night) signed off by a parent/guardian.","needsReview":["Exact current minimum age for the 4-hour Driver Awareness Program vs full 30-hour course","Whether the 6 BTW hours must be with a commercial school or can be parent-taught under any circumstance","Current statutory citation for the under-18 cell phone ban (CRS 42-4-239)","Exact wording of post-6-month passenger rule and sibling exception","Whether nighttime restriction is 12 a.m.-5 a.m. or midnight-5 a.m. statutorily","Permit-holding requirement for applicants who turn 16.5 or 17 without prior permit","Required night-driving hours within the 50-hour log (commonly 10)"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
