INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-gdl-restrictions-daily-life_2', 'quiz_co_co-gdl-restrictions-daily-life', 'A 17-year-old Colorado driver is at a red light. Is it legal for them to send a quick text?', '["Yes, because the car is stopped","Yes, if it''s to a parent","No - under 18 cannot use a phone while driving at all, with very narrow emergency exceptions","Only if using hands-free voice-to-text"]', 2, 'Colorado bans all wireless device use - handheld OR hands-free - by drivers under 18, even when stopped at a light. The only legal exception is reporting a genuine emergency.', 2
