INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-gdl-restrictions-daily-life_3', 'quiz_co_co-gdl-restrictions-daily-life', 'A new Colorado teen driver works the closing shift at a restaurant and has to drive home at 12:30 a.m. What lets them legally do this?', '["Nothing - the curfew has no exceptions","A signed letter or documentation from their employer in the vehicle","Having their work uniform on","Driving under 25 mph"]', 1, 'Driving to/from work is an allowed exception to the nighttime curfew, but teens must carry written documentation (such as an employer letter) verifying the work obligation.', 3
