INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-gdl-restrictions-daily-life_4', 'quiz_co_co-gdl-restrictions-daily-life', 'If a Colorado teen driver is pulled over and their 15-year-old passenger isn''t wearing a seat belt, who can be ticketed?', '["Only the passenger","Only the parent who owns the car","The teen driver - drivers under 18 are responsible for all passengers being belted","No one, because seat belt laws don''t apply to passengers under 16"]', 2, 'Colorado''s teen seat belt law makes the driver under 18 responsible for ensuring every passenger, regardless of age or seat position, is properly restrained.', 4
