INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-state-rules-and-quirks_0', 'quiz_co_co-state-rules-and-quirks', 'You''re descending a long mountain pass on I-70. What''s the safest way to control your speed?', '["Ride the brake pedal continuously to maintain a steady speed","Shift to a lower gear and use engine braking, applying brakes intermittently","Put the car in neutral to save fuel and brake when needed","Turn off cruise control but stay in the highest gear"]', 1, 'On long mountain descents, shifting to a lower gear lets engine braking do most of the work. Riding the brakes continuously causes brake fade - the brakes overheat and lose stopping power.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-state-rules-and-quirks_1', 'quiz_co_co-state-rules-and-quirks', 'Under Colorado''s Move Over law, what must you do when approaching a stopped emergency vehicle with flashing lights?', '["Stop completely until the vehicle leaves","Honk to acknowledge the vehicle","Move over one lane if safe, or slow to at least 20 mph below the speed limit","Maintain your speed and pass cautiously"]', 2, 'Colorado''s Move Over law requires you to change lanes away from the stopped vehicle if safe, or to slow to at least 20 mph below the posted limit (10 mph below if the limit is 25 mph or less).', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-state-rules-and-quirks_2', 'quiz_co_co-state-rules-and-quirks', 'A deer suddenly steps into the road in front of you on a Colorado highway. What''s the recommended response?', '["Swerve sharply to avoid it, even into oncoming lanes","Speed up to get past before it moves","Brake hard and stay in your lane","Honk and close your eyes"]', 2, 'Brake hard but do not swerve. Swerving into oncoming traffic or off the road causes more serious injuries and deaths than hitting the animal would. Stay in your lane and reduce speed as much as possible.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-state-rules-and-quirks_3', 'quiz_co_co-state-rules-and-quirks', 'When passing a bicyclist on a Colorado road, how much space must you leave?', '["At least 1 foot","At least 2 feet","At least 3 feet","At least 5 feet"]', 2, 'Colorado law requires a minimum of 3 feet of clearance when passing a bicyclist. Drivers may legally cross a double-yellow line to provide that space when it''s safe to do so.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_co_co-state-rules-and-quirks_4', 'quiz_co_co-state-rules-and-quirks', 'A 19-year-old driver in Colorado is pulled over and a blood test shows a blood alcohol content of 0.03%. What''s the likely outcome under Colorado law?', '["Nothing - they are under the 0.08% adult DUI limit","A warning, since they are over 18","A DUI charge under Colorado''s zero-tolerance law for drivers under 21","Only a fine for the open container law"]', 2, 'Colorado has a zero-tolerance law for drivers under 21: any blood alcohol level of 0.02% or higher results in a DUI-related charge (commonly UDD - Underage Drinking and Driving), even though it''s below the 0.08% adult limit.', 4
);

