INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ct_ct-gdl-restrictions-daily-life_2', 'quiz_ct_ct-gdl-restrictions-daily-life', 'Can a 17-year-old Connecticut driver use a hands-free Bluetooth headset to make a call while driving?', '["Yes, hands-free is always legal","Yes, but only on highways","No, all mobile device use is banned for drivers under 18","Only if the call is under 5 minutes"]', 2, 'Connecticut bans all mobile electronic device use — including hands-free — for drivers under 18.', 2
