INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ct_ct-gdl-restrictions-daily-life_3', 'quiz_ct_ct-gdl-restrictions-daily-life', 'When can a Connecticut teen driver carry non-family-member passengers (like friends)?', '["After 6 months of licensure","After 1 year of licensure","After turning 17","Immediately upon licensing"]', 1, 'Non-family passengers are not allowed for the full first year of licensure in Connecticut.', 3
