INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_dc_teen_1_0_0', 'rp_dc_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":0,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":0,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":40,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-DC","minPermitAge":16,"classroomHoursCompleted":{"gte":0}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"District of Columbia Department of Motor Vehicles (DC DMV)","minPermitAge":16,"minLicenseAge":17,"minPermitDurationMonths":6,"nighttimeRestriction":"Provisional license holders may not drive between 11:00 PM and 6:00 AM Sunday through Thursday, and between 12:01 AM and 6:00 AM on Friday and Saturday (with limited exceptions for work, school, or medical purposes).","passengerRestriction":"During the first 6 months of a provisional license, no passengers under 21 (other than immediate family). During the next 6 months, no more than two passengers under 21.","cellPhoneRule":"DC prohibits all drivers from using a hand-held cell phone or any handheld communication device while driving. For drivers under 18, all cell phone use (including hands-free) is prohibited. Texting is banned for all drivers.","notes":"DC does not statutorily mandate a specific number of classroom hours or behind-the-wheel instructor hours for teen licensing, but it does require 40 hours of supervised practice (including at least 10 hours at night) logged before a provisional license can be issued. Applicants under 18 must have parental consent and proof of school enrollment or graduation. DC uses a three-tier graduated licensing system: Learner Permit, Provisional License, and Full License (issued at age 18 with clean driving record).","needsReview":["Exact statutory citation for nighttime curfew hours and weekend variation","Whether DC formally accepts driver education completion certificates from private schools to waive any requirements","Current fee schedule for learner permit and provisional license","Whether the 10 nighttime supervised practice hours are codified or guidance","Exact rules around out-of-state permit transfers for new DC residents under 18"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
