  'rpv_de_teen_1_0_0', 'rp_de_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Level 1 Learner''s Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":7,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-DE","minPermitAge":16,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Delaware Division of Motor Vehicles (DMV)","minPermitAge":16,"minLicenseAge":17,"minPermitDurationMonths":12,"nighttimeRestriction":"No driving between 10:00 PM and 6:00 AM during the first 6 months of Level 1 permit, and continuing restrictions during Level 2 (intermediate) phase.","passengerRestriction":"Only one non-family passenger permitted in addition to a licensed adult 25 or older while holding a Level 1 permit; passenger limits continue into the intermediate license phase.","cellPhoneRule":"All drivers under 18 are prohibited from using any handheld OR hands-free cell phone or wireless communication device while driving. Statewide, all drivers are banned from handheld device use; texting while driving is illegal for everyone.","notes":"Delaware operates a two-tier Graduated Driver License (GDL) program. Teens enter Level 1 (Learner''s Permit) at age 16 after completing an approved Delaware Driver Education course (offered through public high schools and approved private providers). After holding the Level 1 permit for at least 6 months conviction-free and 12 months total, plus completing 50 hours of supervised practice (10 of which must be at night), teens advance to a Level 2 (Intermediate) license. Full unrestricted licensure occurs at age 17. The state-approved driver education course is 30 hours of classroom plus 7 hours behind-the-wheel and is typically completed in 10th grade through DOE-approved programs.","needsReview":["Exact current fee schedule for Class D license and permit issuance","Whether private driver education providers are licensed by DelDOT, DOE, or DMV (course approval pathway)","Precise nighttime exemptions for work, school, or religious activities under Level 1 vs Level 2","Current rules around out-of-state driver education reciprocity for new Delaware residents under 18","Whether Delaware accepts electronic submission of driver education completion certificates or still requires paper Blue/Orange forms"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
