INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_de_delaware-gdl-restrictions-daily-life_2', 'quiz_de_delaware-gdl-restrictions-daily-life', 'What happens to the Level 1 Permit holding period if a teen is convicted of a moving violation?', '["Nothing, the clock keeps running","The 6-month conviction-free clock restarts","The permit is automatically revoked","The teen must retake driver education"]', 1, 'A moving violation conviction restarts the 6-month conviction-free portion of the Level 1 holding period, delaying advancement to Level 2.', 2
