INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_de_delaware-rules-and-quirks_2', 'quiz_de_delaware-rules-and-quirks', 'On an undivided road, how must you respond to a stopped school bus with flashing red lights and an extended stop arm?', '["Only traffic behind the bus must stop","Traffic in both directions must stop at least 20 feet away","Slow to 15 mph and pass with caution","Stop only if children are visible"]', 2, 'On an undivided road in Delaware, traffic in BOTH directions must stop at least 20 feet from a school bus with flashing red lights and an extended stop arm. Only on a divided highway with a physical median may oncoming traffic proceed with caution.', 2
