INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_de_delaware-rules-and-quirks_3', 'quiz_de_delaware-rules-and-quirks', 'Which Delaware corridor is known for rapid speed-limit changes and heavy pedestrian/bicycle traffic in summer?', '["I-495 through Wilmington","Route 1 (Coastal Highway) through the beach towns","Route 9 along the Delaware Bay","I-95 near the Maryland line"]', 1, 'Route 1 through Rehoboth, Dewey, Bethany, and Fenwick has rapidly changing speed limits and heavy pedestrian and bicycle activity, especially in summer.', 3
