INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_de_delaware-rules-and-quirks_4', 'quiz_de_delaware-rules-and-quirks', 'What is the most common reason Delaware DMV examiners cite when teens fail the road test?', '["Parallel parking errors","Failure to fully yield on unprotected left turns","Speeding in residential zones","Improper mirror adjustment"]', 1, 'Examiners frequently identify failure to properly yield on unprotected left turns, particularly on busy multi-lane corridors like Route 13 and Route 40, as the leading cause of road test failures.', 4
);

