INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_fl_florida-gdl-restrictions-in-daily-life_1', 'quiz_fl_florida-gdl-restrictions-in-daily-life', 'Which of the following is a valid exception to Florida''s nighttime driving restriction for a 17-year-old?', '["Driving home from a friend''s house after a movie","Driving directly to or from work","Driving to pick up late-night food","Driving to a gas station to refuel"]', 1, 'The two recognized exceptions are being accompanied by a licensed driver 21 or older in the front seat, or driving directly to or from work.', 1
