INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_fl_florida-gdl-restrictions-in-daily-life_2', 'quiz_fl_florida-gdl-restrictions-in-daily-life', 'What is Florida''s GDL passenger restriction for newly licensed teens?', '["No passengers under 18 for the first 6 months","Only one non-family passenger for the first year","Florida has no specific GDL passenger limit","No passengers at all for the first 90 days"]', 2, 'Unlike many states, Florida''s GDL program does not impose a specific passenger limit on teen drivers, although all passengers must follow seatbelt laws.', 2
