INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_fl_florida-gdl-restrictions-in-daily-life_3', 'quiz_fl_florida-gdl-restrictions-in-daily-life', 'Under Florida''s Wireless Communications While Driving Law, hand-held cell phone use is illegal in which areas?', '["Everywhere in the state at all times","Only on interstate highways","In active school zones and work zones","Only between sunset and sunrise"]', 2, 'Hand-held use is banned in active school zones and work zones statewide, and texting while driving is banned everywhere as a primary offense.', 3
