INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_fl_florida-specific-road-rules-and-quirks_1', 'quiz_fl_florida-specific-road-rules-and-quirks', 'On a two-way undivided Florida road, what must you do when a school bus stops with its stop arm extended?', '["Only traffic behind the bus must stop","Traffic in both directions must stop","You may proceed slowly past the bus","Only stop if children are visible"]', 1, 'On an undivided two-way road, traffic in both directions must stop. Only on divided highways with a raised barrier or 5-foot median may oncoming traffic continue.', 1
