INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_fl_florida-specific-road-rules-and-quirks_2', 'quiz_fl_florida-specific-road-rules-and-quirks', 'When are Florida drivers required to use headlights, beyond the standard sunset-to-sunrise rule?', '["Only when visibility is below 500 feet","Whenever the radio is on","Whenever windshield wipers are in continuous use due to weather","Only on interstate highways"]', 2, 'Florida requires headlights whenever wipers are in continuous use for rain or fog, and whenever weather limits visibility to 1,000 feet or less.', 2
