INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_fl_florida-specific-road-rules-and-quirks_3', 'quiz_fl_florida-specific-road-rules-and-quirks', 'When does Florida''s official hurricane season run?', '["May 1 through October 31","June 1 through November 30","July 1 through December 31","Year-round, with no defined season"]', 1, 'The Atlantic hurricane season, which governs Florida, officially runs from June 1 through November 30.', 3
