INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_fl_florida-specific-road-rules-and-quirks_4', 'quiz_fl_florida-specific-road-rules-and-quirks', 'How much clearance must a Florida driver give when passing a bicyclist?', '["At least 1 foot","At least 2 feet","At least 3 feet","At least 5 feet"]', 2, 'Florida law requires at least 3 feet of clearance when passing a cyclist.', 4
