  'rpv_ga_teen_1_0_0', 'rp_ga_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Class CP Instructional Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":40,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-GA","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Georgia Department of Driver Services (DDS)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":12,"nighttimeRestriction":"Class D license holders (under 18) may not drive between 12:00 a.m. and 6:00 a.m. for any reason — no exceptions for work, school, or family.","passengerRestriction":"First 6 months with Class D: no passengers other than immediate family. Months 6-12: no more than 1 non-family passenger under age 21. After 12 months: no more than 3 non-family passengers under 21.","cellPhoneRule":"Drivers under 18 may not use any wireless telecommunications device while driving — handheld or hands-free. Georgia''s statewide Hands-Free Law also bans handheld phone use for all drivers regardless of age.","notes":"Georgia''s Teenage and Adult Driver Responsibility Act (TADRA) and Joshua''s Law set the framework. Joshua''s Law requires anyone under 17 applying for a Class D license to have completed an approved 30-hour classroom driver education course PLUS 40 hours of supervised driving (6 of which must be at night), certified by a parent/guardian via Form DS-1. Applicants 17 or older are not required to complete Joshua''s Law but still must hold the permit 12 months and 1 day. The instructional permit (Class CP) requires passing a vision exam, knowledge test, and parental consent if under 18.","needsReview":["Exact wording of Form DS-1 certification requirements as of 2026","Whether DDS now offers any electronic submission path for course completion certificates (currently treated as manual)","Most recent fee schedule for Class CP and Class D issuance","Whether the 6 required nighttime practice hours count toward the 40-hour total or are additional"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
