INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-gdl-restrictions-daily-life_0', 'quiz_ga_georgia-gdl-restrictions-daily-life', 'A Class D driver under 18 finishes a work shift at 11:55 p.m. Under Georgia law, what is true about her drive home?', '["She may drive home because work is an exception to the curfew","She may drive only if a parent gives her written permission","She may not drive after 12:00 a.m. — Georgia''s curfew has no work exception","The curfew only applies on weekends"]', 2, 'Georgia''s curfew for under-18 Class D holders is midnight to 6 a.m. with no exceptions — work, school, or otherwise.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-gdl-restrictions-daily-life_1', 'quiz_ga_georgia-gdl-restrictions-daily-life', 'During the FIRST 6 months of holding a Class D license, a driver under 18 may carry which passengers?', '["Up to 3 friends under 21","Only immediate family members","One non-family passenger under 21","Anyone, as long as all wear seat belts"]', 1, 'For the first 6 months of Class D, passengers are limited to immediate family. Non-family passengers under 21 are not permitted yet.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-gdl-restrictions-daily-life_2', 'quiz_ga_georgia-gdl-restrictions-daily-life', 'Under Georgia law, a Class D driver under 18 wants to use a hands-free Bluetooth phone call while driving. Is this allowed?', '["Yes, hands-free is always allowed","Yes, but only for calls to a parent","No — drivers under 18 may not use any wireless device, hands-free or otherwise (except to report an emergency)","Yes, but only on highways"]', 2, 'Drivers under 18 in Georgia are prohibited from using ANY wireless device while driving, including hands-free, except to report an emergency.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-gdl-restrictions-daily-life_3', 'quiz_ga_georgia-gdl-restrictions-daily-life', 'Which conviction will automatically suspend a Class D license under TADRA?', '["A parking ticket","Driving 24 mph or more over the speed limit","A burned-out headlight","Forgetting to renew the registration"]', 1, 'Speeding 24+ mph over the limit is one of several offenses that trigger automatic suspension for TADRA-eligible drivers.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-gdl-restrictions-daily-life_4', 'quiz_ga_georgia-gdl-restrictions-daily-life', 'Eight months after getting her Class D, a 17-year-old wants to drive friends to a basketball game. How many non-family passengers under 21 may legally ride with her?', '["0","1","3","Unlimited"]', 1, 'Between months 6 and 12 of holding a Class D, the driver may have only ONE non-family passenger under age 21.', 4
