INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-specific-rules-and-quirks_1', 'quiz_ga_georgia-specific-rules-and-quirks', 'Georgia''s Super Speeder law adds a $200 state fee for being convicted of driving at what speed?', '["65 mph or more on any road","75 mph or more on a two-lane road, or 85 mph or more on any road","Any speed 10 mph over the limit","Only for racing on a highway"]', 1, 'The Super Speeder fee applies to convictions of 75+ mph on a two-lane road OR 85+ mph on any road, in addition to local fines.', 1
