INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-specific-rules-and-quirks_2', 'quiz_ga_georgia-specific-rules-and-quirks', 'Under Georgia''s Move Over Law, what must you do when approaching a stationary emergency or tow vehicle with flashing lights?', '["Honk to alert them","Move one lane away if safe; otherwise slow below the speed limit and be prepared to stop","Maintain your speed and pass quickly","Stop completely until they leave"]', 1, 'Move Over requires changing one lane away if safe, or slowing below the speed limit and being prepared to stop if a lane change isn''t possible.', 2
