INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-specific-rules-and-quirks_3', 'quiz_ga_georgia-specific-rules-and-quirks', 'Georgia''s Zero Tolerance law sets the BAC limit for drivers UNDER 21 at:', '["0.00","0.02","0.05","0.08"]', 1, 'Drivers under 21 in Georgia face a 0.02 BAC limit under Zero Tolerance; a first conviction triggers a 6-month suspension.', 3
