INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ga_georgia-specific-rules-and-quirks_4', 'quiz_ga_georgia-specific-rules-and-quirks', 'You''re driving on a four-lane road with a grass median when a school bus traveling the OPPOSITE direction stops with flashing red lights. What must you do?', '["Stop, even though a median separates you","Slow down and pass with caution — only same-direction traffic must stop on a divided highway","Pull off onto the shoulder","Sound your horn and proceed"]', 1, 'On a divided highway with a physical median, only traffic traveling in the same direction as the bus must stop. Oncoming traffic across a median may proceed with caution.', 4
);

