INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_hi_hawaii-specific-road-rules-and-quirks_1', 'quiz_hi_hawaii-specific-road-rules-and-quirks', 'Driving over 80 mph anywhere in Hawaii is classified as what?', '["A standard traffic infraction","A civil-only fine","Excessive Speeding, a criminal offense","Reckless driving only if a crash occurs"]', 2, 'Going over 80 mph (or 30+ mph over the posted limit) is the criminal offense of Excessive Speeding in Hawaii, with potential jail time.', 1
