INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_hi_hawaii-specific-road-rules-and-quirks_2', 'quiz_hi_hawaii-specific-road-rules-and-quirks', 'What is the customary rule at Hawaii''s many one-lane bridges?', '["Larger vehicles always have right of way","Honk loudly before entering","First to arrive crosses; if a line is waiting on the other side, wait for the group to pass before your side proceeds","Vehicles going uphill always yield"]', 2, 'The first vehicle to arrive goes first, but groups of about 5–7 cars typically take turns crossing — and you should follow local practice.', 2
