INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_hi_hawaii-specific-road-rules-and-quirks_3', 'quiz_hi_hawaii-specific-road-rules-and-quirks', 'Why is Hawaii pavement especially slick in the first few minutes of rain?', '["The asphalt is colder than mainland asphalt","Oils and residues (and embedded coral) rise to the surface before being washed away","Hawaii uses a unique low-friction sealcoat","Salt spray from the ocean coats the road"]', 1, 'Accumulated oils rise to the surface in the first minutes of rain, making roads — especially older coral-aggregate asphalt — extremely slick.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_hi_hawaii-specific-road-rules-and-quirks_4', 'quiz_hi_hawaii-specific-road-rules-and-quirks', 'What kind of insurance state is Hawaii?', '["Tort (at-fault) state","No-fault state","Self-insurance only","State-run insurance pool"]', 1, 'Hawaii is a no-fault insurance state — your own policy covers your medical costs in minor crashes regardless of fault.', 4
);

