INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ia_iowa-specific-rules-and-quirks_0', 'quiz_ia_iowa-specific-rules-and-quirks', 'Who is the Iowa Minor School License primarily designed for?', '["Urban teens who want to drive to social events","Rural students who live more than one mile from school","College students under 18","Out-of-state students attending Iowa schools"]', 1, 'The Minor School License is designed for students (typically around age 14.5) who live more than one mile from school, allowing limited driving along approved routes.', 0
