INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ia_iowa-specific-rules-and-quirks_1', 'quiz_ia_iowa-specific-rules-and-quirks', 'Under Iowa''s Move Over Law, when you approach a stopped emergency or maintenance vehicle with flashing lights, you must:', '["Maintain speed and stay in your lane","Honk to acknowledge them","Change to a non-adjacent lane if safe, otherwise slow down significantly","Stop completely until they wave you past"]', 2, 'Iowa requires drivers to move over to a non-adjacent lane when safe, or slow down well below the speed limit if moving over isn''t possible.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ia_iowa-specific-rules-and-quirks_2', 'quiz_ia_iowa-specific-rules-and-quirks', 'Iowa''s ''wipers-on, lights-on'' rule means:', '["Headlights must be on whenever the windshield wipers are operating due to weather","Wipers must be on whenever headlights are on","Only required at night","Only required on interstates"]', 0, 'Iowa law requires headlights to be on whenever your wipers are operating because of precipitation, and any time visibility is below 500 feet.', 2
