INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ia_iowa-specific-rules-and-quirks_3', 'quiz_ia_iowa-specific-rules-and-quirks', 'What is the blood alcohol concentration limit for Iowa drivers under age 21?', '["0.00%","0.02%","0.05%","0.08%"]', 1, 'Iowa''s zero-tolerance law sets the limit at 0.02% BAC for drivers under 21, with license suspension as the consequence.', 3
