INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ia_iowa-specific-rules-and-quirks_4', 'quiz_ia_iowa-specific-rules-and-quirks', 'When following a tractor or combine displaying the orange slow-moving vehicle emblem on a rural Iowa road, the safest action is to:', '["Pass immediately, even on a hill or curve","Tailgate to encourage the operator to speed up","Stay back, watch for turns into field entrances, and pass only when you have a clear straight view","Use the shoulder to pass"]', 2, 'Farm equipment often turns into field entrances without much warning. Stay back, be patient, and pass only with a long, clear, straight stretch of road.', 4
