INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_id_teen_1_0_0', 'rp_id_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Supervised Instruction Permit (SIP)","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-ID","minPermitAge":14.5,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Idaho Transportation Department, Division of Motor Vehicles","minPermitAge":14.5,"minLicenseAge":15,"minPermitDurationMonths":6,"nighttimeRestriction":"Drivers under 17 may not drive between sunset and sunrise unless accompanied by a licensed driver age 21 or older.","passengerRestriction":"During the first 6 months of licensure, drivers under 17 may not transport more than one passenger under age 17 who is not an immediate family member.","cellPhoneRule":"Idaho prohibits handheld use of a mobile electronic device (including texting and calls) by all drivers statewide; the only exceptions are hands-free use and emergency calls. Drivers under 17 should treat the vehicle as a no-phone zone.","notes":"Idaho requires teens under 17 to complete a state-approved driver education course (30 hours classroom + 6 hours behind-the-wheel + 6 hours observation) before getting a Supervised Instruction Permit. The SIP must be held for at least 6 months with no traffic violations before applying for a driver''s license. Teens must log at least 50 hours of supervised practice (including 10 hours at night) during the permit period. The driver''s license is restricted until age 17.","needsReview":["Exact minimum age (14.5 vs 15) for SIP eligibility — Idaho rule is completion of driver ed plus age 14.5","Whether observation hours (6) count toward the ''required BTW'' total or are reported separately","Exact passenger restriction text and family exemption wording","Current statewide handheld device statute citation and effective date","Whether nighttime restriction ends at 17 or upon obtaining unrestricted license","Supervised practice log requirement of 50 hours including 10 night hours — verify current ITD rule"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
