INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_how-to-get-an-idaho-permit_1', 'quiz_id_how-to-get-an-idaho-permit', 'Which agency issues Idaho driver permits and licenses?', '["Idaho Department of Public Safety","Idaho State Police","Idaho Transportation Department, Division of Motor Vehicles","Idaho Secretary of State"]', 2, 'The Idaho Transportation Department (ITD) Division of Motor Vehicles is responsible for driver licensing, working through county sheriff DMV offices.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_how-to-get-an-idaho-permit_2', 'quiz_id_how-to-get-an-idaho-permit', 'Driver education for an Idaho teen under 17 requires which combination of hours?', '["20 classroom + 6 BTW + 6 observation","30 classroom + 6 BTW + 6 observation","30 classroom + 10 BTW + 0 observation","40 classroom + 4 BTW + 4 observation"]', 1, 'Idaho requires 30 hours of classroom instruction, 6 hours of behind-the-wheel driving, and 6 hours of in-car observation.', 2
