INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_how-to-get-an-idaho-permit_3', 'quiz_id_how-to-get-an-idaho-permit', 'How long must an Idaho teen hold the SIP — and under what conditions — before applying for a driver''s license?', '["3 months with no more than one violation","6 months with no traffic violations","6 months regardless of violations","12 months with no traffic violations"]', 1, 'The SIP must be held for at least 6 months with NO traffic violations. Any violation resets the 6-month clock.', 3
