INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_idaho-gdl-restrictions-daily-life_1', 'quiz_id_idaho-gdl-restrictions-daily-life', 'During the first 6 months after licensure, a 16-year-old Idaho driver may transport:', '["No passengers at all","Only immediate family members","One non-family passenger under 17, plus any number of immediate family members","Up to three friends under 17"]', 2, 'Idaho limits drivers under 17 to one non-family passenger under 17 during the first 6 months. Immediate family (siblings/household minors) don''t count toward the limit.', 1
