INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_idaho-gdl-restrictions-daily-life_2', 'quiz_id_idaho-gdl-restrictions-daily-life', 'Idaho''s handheld device law applies to:', '["Only drivers under 18","Only drivers with a SIP","All drivers statewide","Only drivers in cities over 50,000 residents"]', 2, 'Idaho''s handheld ban is statewide and applies to every driver. Hands-free and emergency 911 calls are the only general exceptions.', 2
