INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_idaho-gdl-restrictions-daily-life_3', 'quiz_id_idaho-gdl-restrictions-daily-life', 'Idaho''s blood alcohol concentration (BAC) limit for drivers under 21 is:', '["0.08%","0.05%","0.02%","0.00%"]', 2, 'Idaho enforces a 0.02% BAC limit for drivers under 21 — effectively zero tolerance. Any detectable alcohol can trigger suspension.', 3
