INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_idaho-gdl-restrictions-daily-life_4', 'quiz_id_idaho-gdl-restrictions-daily-life', 'What happens if a 16-year-old Idaho driver gets a moving violation during the first 6 months after licensure?', '["Nothing — only SIP-period violations matter","It can reset the 6-month clean-record clock needed to lift the passenger restriction","Their license is automatically revoked","Only their parents are fined"]', 1, 'Violations during the post-license GDL period can reset the clean-record clock and delay when the passenger restriction lifts.', 4
