INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_idaho-specific-rules-and-quirks_2', 'quiz_id_idaho-specific-rules-and-quirks', 'If a deer suddenly appears in front of you on a highway, the safest reaction is to:', '["Swerve sharply to avoid it","Accelerate to pass before it crosses","Brake hard and stay in your lane","Flash your high beams and continue at the same speed"]', 2, 'Swerving at highway speed often causes worse crashes than the animal impact. Brake hard, stay in your lane, and stay on the road.', 2
