INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_idaho-specific-rules-and-quirks_3', 'quiz_id_idaho-specific-rules-and-quirks', 'On an Idaho ''open range'' road, if your vehicle strikes a cow:', '["The rancher is always liable for vehicle damage","You may be liable for the value of the animal","The state pays for both the cow and your repairs","There are no legal consequences — it''s a no-fault zone"]', 1, 'On open range, ranchers generally aren''t required to fence livestock. Drivers may owe the animal''s value and bear their own vehicle damage.', 3
