INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_id_idaho-specific-rules-and-quirks_4', 'quiz_id_idaho-specific-rules-and-quirks', 'Studded snow tires are legal in Idaho:', '["Year-round with no restrictions","Only October 1 through April 30","Only November 15 through March 15","Only on vehicles registered in mountain counties"]', 1, 'Idaho allows studded tires from October 1 through April 30. Using them outside that window can result in a fine.', 4
