INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_il_teen_1_0_0', 'rp_il_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-IL","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Illinois Secretary of State","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":9,"nighttimeRestriction":"Drivers under 17 may not drive between 10:00 PM and 6:00 AM Sunday through Thursday, or between 11:00 PM and 6:00 AM Friday and Saturday.","passengerRestriction":"For the first 12 months of licensure (or until age 18, whichever comes first), drivers under 18 are limited to one passenger under age 20 who is not a sibling, stepsibling, child, or stepchild.","cellPhoneRule":"Drivers under 19 are prohibited from using any cell phone, including hands-free devices, while driving except in emergencies. All Illinois drivers are prohibited from texting or hand-held cell phone use while driving.","notes":"Illinois has a robust three-tier Graduated Driver Licensing (GDL) program with the Permit Phase (9 months), Initial Licensing Phase (12 months), and Full Licensing Phase (age 18+). Teens 15-17 must complete a state-approved driver education course (30 hours classroom + 6 hours behind-the-wheel) before getting an instruction permit. Of the 50 required practice hours, at least 10 must be at night. Parent/guardian signature is required for applicants under 18. Illinois does not use a separate physical credential like Minnesota''s Blue Card; completion is verified via the school''s submission of records to the Secretary of State, typically through the Driver Education Certificate of Completion.","needsReview":["permitCredentialDeliveryMode - Illinois schools historically submit completion via paper certificate but electronic submission may now be available; confirm current SOS process","Exact nighttime curfew hours - verify weekday vs weekend split is still 10pm/11pm cutoff","Whether the 9-month permit duration applies to all teens or just under-18 applicants","Current cell phone rule wording for under-19 drivers - law has been amended multiple times"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
