  'q_il_illinois-specific-rules-and-quirks_0', 'quiz_il_illinois-specific-rules-and-quirks', 'Under Scott''s Law, what must an Illinois driver do when approaching a stationary emergency vehicle with flashing lights?', '["Maintain speed but honk a warning","Slow down and change lanes away from the vehicle if safe","Come to a complete stop in the current lane","Flash headlights and proceed normally"]', 1, 'Scott''s Law requires drivers to slow down and, when safe, move over to a lane away from any stationary emergency, tow, or maintenance vehicle with flashing lights.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_il_illinois-specific-rules-and-quirks_1', 'quiz_il_illinois-specific-rules-and-quirks', 'When must Illinois drivers turn on their headlights according to state law?', '["Only between sunset and sunrise","Only when visibility is under 500 feet","Whenever windshield wipers are in continuous use","Only during officially declared weather emergencies"]', 2, 'Illinois law requires headlights to be on any time the windshield wipers are being used continuously due to rain, snow, or fog.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_il_illinois-specific-rules-and-quirks_2', 'quiz_il_illinois-specific-rules-and-quirks', 'What is the legal blood alcohol concentration (BAC) threshold for an Illinois driver under age 21?', '["0.08","0.05","0.02","Zero tolerance — any detectable amount"]', 3, 'Illinois has a zero tolerance policy for drivers under 21. Any detectable amount of alcohol results in license suspension.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_il_illinois-specific-rules-and-quirks_3', 'quiz_il_illinois-specific-rules-and-quirks', 'On a four-lane road with two lanes going each direction, a school bus stops with red lights flashing in the oncoming lanes. What must you do?', '["Stop and wait for the bus to proceed","Slow to 20 mph and pass cautiously","Proceed with caution — only same-direction traffic must stop","Pull over to the shoulder and wait"]', 2, 'On roads with four or more lanes, only vehicles traveling in the same direction as the bus must stop. Oncoming traffic may proceed with caution.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_il_illinois-specific-rules-and-quirks_4', 'quiz_il_illinois-specific-rules-and-quirks', 'When entering a roundabout in Illinois, you must:', '["Yield to traffic already in the circle","Stop completely at the yield sign every time","Proceed first if you arrive at the same moment","Signal left to indicate you''re entering"]', 0, 'Traffic already circulating in a roundabout has the right of way. Entering drivers must yield and only proceed when there is a safe gap.', 4
