  'rpv_in_teen_1_0_0', 'rp_in_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner''s Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-IN","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Indiana Bureau of Motor Vehicles (BMV)","minPermitAge":15,"minLicenseAge":16.25,"minPermitDurationMonths":6,"nighttimeRestriction":"For the first 180 days after licensing, no driving between 10:00 PM and 5:00 AM Sunday-Friday, and between 11:00 PM and 5:00 AM on Friday and Saturday nights. After 180 days and until age 18, no driving between 1:00 AM and 5:00 AM.","passengerRestriction":"For the first 180 days after licensing, the driver may not transport any passengers other than immediate family members (parent/guardian/sibling/spouse/child) unless accompanied by a licensed driver age 25+.","cellPhoneRule":"Drivers under 21 are prohibited from using any telecommunications device while driving, except to call 911 in an emergency. Indiana also has a statewide hands-free law (effective 2020) prohibiting all drivers from holding a mobile device while operating a vehicle.","notes":"Indiana requires a state-approved driver education course (classroom + behind-the-wheel) for anyone wanting a license before age 18. A teen who completes approved driver ed may apply for the probationary license at 16 years and 3 months; without driver ed, the minimum is 16 years and 9 months. The learner''s permit can be obtained at 15 if enrolled in an approved driver ed program, otherwise at 16. Supervised practice driving log of 50 hours (10 at night) must be signed by parent/guardian. Indiana uses a ''probationary license'' for drivers under 21 with GDL restrictions that lift in stages.","needsReview":["Exact minLicenseAge representation (16.25 = 16 years 3 months with driver ed; 16.75 without)","Whether learner''s permit minimum is strictly 15 only with concurrent enrollment in driver ed","Current BMV-required behind-the-wheel hour count (6 is standard for approved courses; verify against latest BMV rule)","Whether telecommunications-device prohibition for under-21 is still separately enforced after the 2020 hands-free law"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
