INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_how-to-get-an-indiana-learners-permit_2', 'quiz_in_how-to-get-an-indiana-learners-permit', 'How many hours of supervised practice driving — and how many of those at night — must be logged before licensing in Indiana?', '["30 hours total, 5 at night","40 hours total, 8 at night","50 hours total, 10 at night","60 hours total, 15 at night"]', 2, 'Indiana requires 50 hours of parent-supervised practice driving, of which at least 10 hours must be after sunset.', 2
