INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_how-to-get-an-indiana-learners-permit_3', 'quiz_in_how-to-get-an-indiana-learners-permit', 'While driving on a learner''s permit in Indiana, who must be in the front passenger seat?', '["Any licensed driver age 18 or older","Any adult age 21 or older","A licensed driver age 25 or older, or a certified driver ed instructor","Only a parent or legal guardian"]', 2, 'Indiana law requires the supervising driver in the front passenger seat to be at least 25 years old and properly licensed, or a certified driver ed instructor.', 3
