INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-gdl-restrictions-daily-life_2', 'quiz_in_indiana-gdl-restrictions-daily-life', 'After holding the probationary license for more than 180 days but still under age 21, what nighttime curfew remains in effect?', '["10:00 PM to 5:00 AM, every night","11:00 PM to 5:00 AM, every night","1:00 AM to 5:00 AM, every night","No curfew at all"]', 2, 'After the first 180 days, Indiana drivers under 21 still may not drive between 1:00 AM and 5:00 AM.', 2
