INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-gdl-restrictions-daily-life_3', 'quiz_in_indiana-gdl-restrictions-daily-life', 'Under Indiana law, when may a driver under 21 use a telecommunications device while driving?', '["Anytime, as long as it''s hands-free","Only to call 911 in an emergency","Only when stopped at a red light","When using a mounted GPS app"]', 1, 'Indiana prohibits drivers under 21 from using any telecommunications device while driving, with the only exception being a 911 emergency call.', 3
