INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-gdl-restrictions-daily-life_4', 'quiz_in_indiana-gdl-restrictions-daily-life', 'Indiana''s hands-free law, which applies to all drivers, prohibits which behavior?', '["Using a Bluetooth headset for a call","Glancing at a mounted GPS","Holding a mobile phone while the vehicle is in operation","Listening to streaming music"]', 2, 'Since 2020, Indiana drivers of any age may not hold a mobile device while the vehicle is in motion. Mounted, voice-activated, or single-tap use is still allowed.', 4
