INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-specific-rules-and-quirks_0', 'quiz_in_indiana-specific-rules-and-quirks', 'You approach a roundabout in Carmel, Indiana. What is the correct action?', '["Stop at the entrance, then proceed when the road is clear","Yield to traffic already circulating in the roundabout","Enter at full speed since roundabouts don''t require yielding","Always come to a complete stop, even if the roundabout is empty"]', 1, 'Indiana roundabouts require entering drivers to yield to traffic already circulating; stopping is only required if necessary to yield.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-specific-rules-and-quirks_1', 'quiz_in_indiana-specific-rules-and-quirks', 'A school bus on a two-lane road stops with its stop arm extended and red lights flashing. What must you do if you are traveling in the opposite direction?', '["Slow to 20 mph and proceed with caution","Continue at the posted speed; only same-direction traffic must stop","Stop and wait until the stop arm retracts and red lights stop flashing","Stop only if children are visibly crossing"]', 2, 'On a two-lane road in Indiana, traffic in BOTH directions must stop for a school bus with its stop arm extended. A painted line or center turn lane does not count as a divided highway.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-specific-rules-and-quirks_2', 'quiz_in_indiana-specific-rules-and-quirks', 'Under Indiana''s Move Over Law, what must you do when passing a stopped tow truck with flashing amber lights?', '["Nothing special — the law only applies to police vehicles","Honk to alert the tow operator","Move over a lane if safe, or slow to at least 10 mph below the posted limit","Come to a complete stop until the tow truck leaves"]', 2, 'Indiana''s Move Over Law applies to any stopped emergency, utility, or road-maintenance vehicle with flashing lights, including tow trucks. Change lanes if safe, or slow to at least 10 mph below the posted speed limit.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-specific-rules-and-quirks_3', 'quiz_in_indiana-specific-rules-and-quirks', 'Indiana law requires headlights to be on in which of the following situations?', '["Only between midnight and 5:00 AM","Anytime wipers are in use due to weather, plus sunset to sunrise","Only when visibility is less than 100 feet","Only during winter months"]', 1, 'Indiana''s wipers-on/lights-on rule requires headlights to be illuminated from sunset to sunrise and anytime weather conditions require windshield wipers.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_in_indiana-specific-rules-and-quirks_4', 'quiz_in_indiana-specific-rules-and-quirks', 'An 18-year-old Indiana driver is pulled over and registers a Blood Alcohol Concentration of 0.04%. What is the legal consequence?', '["Nothing — they are under the 0.08% limit","A written warning only","An OWI charge under Indiana''s zero-tolerance law for drivers under 21","A fine but no license suspension"]', 2, 'Indiana applies a zero-tolerance standard to drivers under 21: a BAC of 0.02% or higher is grounds for an OWI charge, regardless of how the driver appears or behaves.', 4
);

