INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ky_kentucky-gdl-restrictions-daily-life_3', 'quiz_ky_kentucky-gdl-restrictions-daily-life', 'What is the rule on cell phone use for Kentucky drivers under 18?', '["Hands-free use is allowed","Texting only is banned, calls are fine","All personal communication device use is prohibited","Use is allowed when stopped at red lights"]', 2, 'Kentucky bans all use of personal communication devices — handheld or hands-free — for drivers under 18.', 3
