INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ky_kentucky-gdl-restrictions-daily-life_4', 'quiz_ky_kentucky-gdl-restrictions-daily-life', 'What blood alcohol concentration triggers Kentucky''s zero-tolerance law for drivers under 21?', '["0.08% or higher","0.05% or higher","0.02% or higher","Any detectable amount"]', 2, 'Kentucky''s zero-tolerance threshold for drivers under 21 is 0.02% BAC, well below the 0.08% adult limit.', 4
