  'rpv_la_teen_1_0_0', 'rp_la_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Temporary Instructional Permit (TIP)","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":8,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-LA","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Louisiana Office of Motor Vehicles (OMV)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Intermediate license holders under 17 may not drive between 11:00 p.m. and 5:00 a.m. unless accompanied by a licensed adult 21 or older, or for limited purposes such as work, school, or religious activities.","passengerRestriction":"Drivers under 17 with an intermediate license may not transport more than one passenger under age 21 who is not an immediate family member between 6:00 p.m. and 5:00 a.m.","cellPhoneRule":"All drivers under 18, and any driver with a learner''s permit or intermediate license regardless of age, are prohibited from using a handheld wireless communication device while driving. Texting while driving is banned for all Louisiana drivers.","notes":"Louisiana uses a three-stage Graduated Driver License (GDL) program: Temporary Instructional Permit (TIP) at 15, Intermediate License at 16, and Full License at 17. Applicants under 18 must complete a state-approved 30-hour classroom plus 8-hour behind-the-wheel driver education course (the ''38-hour'' course). Applicants 18 and older may instead complete a 6-hour pre-licensing course. A parent or legal guardian must sign for any minor applicant, and proof of school enrollment or a high school equivalency is required for minors under the state''s compulsory attendance law. The OMV accepts course completion certificates issued by licensed third-party driving schools; submission is typically a paper certificate handed to the OMV clerk at the field office.","needsReview":["Exact statutory citation for nighttime curfew hours (11 p.m.-5 a.m. vs. midnight-5 a.m.) — verify against current RS 32:407","Whether the 50-hour supervised practice requirement is statutorily mandated or only strongly recommended in LA","Current delivery mode for course completion certificates — OMV may now accept electronic submissions from licensed schools in some parishes","Exact passenger restriction wording and age cutoffs — verify against current OMV handbook","Whether the intermediate license stage ends at age 17 exactly or has additional conditions"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
