INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_la_how-to-get-a-louisiana-permit_1', 'quiz_la_how-to-get-a-louisiana-permit', 'How many hours of driver education are required for a Louisiana applicant under 18?', '["6 hours of pre-licensing only","20 hours classroom plus 4 hours BTW","30 hours classroom plus 8 hours behind-the-wheel (38 total)","50 hours classroom only"]', 2, 'Minors must complete the full ''38-hour course'' — 30 hours of classroom plus 8 hours of behind-the-wheel instruction with a licensed school.', 1
