INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_la_how-to-get-a-louisiana-permit_2', 'quiz_la_how-to-get-a-louisiana-permit', 'What is the minimum holding period for the TIP before moving to an Intermediate License?', '["30 days","90 days","180 days (6 months)","1 year"]', 2, 'The TIP must be held for at least 180 days (6 months) with a clean driving record before you can advance to the Intermediate License stage.', 2
