INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_la_louisiana-specific-rules-and-quirks_3', 'quiz_la_louisiana-specific-rules-and-quirks', 'Which of the following left turns on red is generally permitted in Louisiana?', '["From a two-way street onto a one-way street","From a one-way street onto another one-way street going the legal direction, after stopping","Any left on red, anywhere","No left on red is ever permitted in Louisiana"]', 1, 'Louisiana allows a left turn on red after a complete stop when going from a one-way street onto another one-way street, unless prohibited by signage.', 3
