INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ma_how-to-get-a-permit-in-massachusetts_3', 'quiz_ma_how-to-get-a-permit-in-massachusetts', 'Permit holders in Massachusetts may NOT drive during which hours, regardless of who is in the car?', '["10:00 p.m. to 6:00 a.m.","11:00 p.m. to 5:00 a.m.","12:00 a.m. to 5:00 a.m.","Permit holders have no time restrictions"]', 2, 'Massachusetts learner''s permit holders are prohibited from driving between 12:00 a.m. and 5:00 a.m. under any circumstances, even with a supervising driver.', 3
