INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ma_ma-jol-restrictions-daily-life_3', 'quiz_ma_ma-jol-restrictions-daily-life', 'What is the consequence of a first speeding offense for a JOL holder in Massachusetts?', '["A warning only","30-day suspension and a fine","90-day suspension plus required retraining course and retesting","Immediate revocation until age 21"]', 2, 'A first speeding offense for a JOL holder triggers a 90-day suspension, mandatory Driver Attitudinal Retraining, reinstatement fees, and required retaking of both the knowledge and road tests.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ma_ma-jol-restrictions-daily-life_4', 'quiz_ma_ma-jol-restrictions-daily-life', 'Which family members are EXEMPT from the JOL passenger restriction during the first 6 months?', '["Cousins","Friends from school","Siblings","Anyone living in your household"]', 2, 'Siblings are explicitly exempt from the JOL passenger restriction. Cousins, friends, and other household members under 18 are not allowed without a qualified adult passenger.', 4
