INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ma_ma-specific-rules-and-quirks_3', 'quiz_ma_ma-specific-rules-and-quirks', 'What does Massachusetts law require drivers to do regarding snow on their vehicle before driving?', '["Nothing — it''s the driver''s choice","Clear only the windshield and side windows","Clear snow and ice from the entire vehicle, including the roof","Clear only enough snow for visibility"]', 2, 'Massachusetts law requires drivers to clear snow and ice from the entire vehicle, including the roof, before driving. Snow flying off your car can cause accidents and result in fines and civil liability.', 3
