INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_me_maine-gdl-restrictions-daily-life_3', 'quiz_me_maine-gdl-restrictions-daily-life', 'Which of these is a valid exception to Maine''s nighttime driving restriction for intermediate drivers?', '["Driving a friend home from a party","Driving to or from work","Driving to get late-night food","Driving for any reason after midnight"]', 1, 'Employment, school activities, and emergencies are the recognized exceptions to the midnight–5:00 a.m. rule.', 3
