INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_me_maine-gdl-restrictions-daily-life_4', 'quiz_me_maine-gdl-restrictions-daily-life', 'What is a typical consequence of violating Maine''s GDL passenger or nighttime restrictions?', '["A warning with no record","Extension of the 9-month restriction period and possible license suspension","Mandatory community service only","Loss of the permit fee"]', 1, 'Maine BMV may extend the restriction period and suspend the intermediate license, often for 30 days on a first offense.', 4
