  'q_me_maine-specific-rules-and-quirks_2', 'quiz_me_maine-specific-rules-and-quirks', 'What is Maine''s legal BAC limit for drivers under 21?', '["0.08%","0.05%","0.02%","0.00% — any detectable alcohol"]', 3, 'Maine has a zero-tolerance law for drivers under 21; any measurable alcohol results in a 1-year suspension.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_me_maine-specific-rules-and-quirks_3', 'quiz_me_maine-specific-rules-and-quirks', 'On a two-lane road in Maine, when a school bus stops with red lights flashing and the stop arm out, who must stop?', '["Only vehicles behind the bus","Only vehicles in the same direction as the bus","Traffic in both directions","No one — Maine has no school bus stop law"]', 2, 'Traffic in both directions must stop unless the roadway is physically divided by a median or barrier.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_me_maine-specific-rules-and-quirks_4', 'quiz_me_maine-specific-rules-and-quirks', 'Under Maine law, when must your headlights be on (besides at night)?', '["Only when it''s snowing heavily","Anytime your windshield wipers are in continuous use","Only when visibility is less than 500 feet","Only on the highway"]', 1, 'Maine''s ''wipers on, lights on'' law requires headlights whenever wipers are in continuous use, plus when visibility is under 1,000 feet.', 4
);

