INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_mi_teen_1_0_0', 'rp_mi_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Temporary Instruction Permit (TIP) - Level 1 License","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":24,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-MI","minPermitAge":14.75,"classroomHoursCompleted":{"gte":24}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Michigan Secretary of State (SOS)","minPermitAge":14.75,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Level 2 (Intermediate): No driving between 10:00 p.m. and 5:00 a.m. unless going to/from work, with a parent/guardian or licensed driver 21+, or for an authorized employment, school, or religious activity.","passengerRestriction":"Level 2 (Intermediate): No more than one passenger under age 21 in the vehicle, unless transporting immediate family, going to/from school or a school-sanctioned event, or accompanied by a parent/guardian or licensed driver 21+.","cellPhoneRule":"Michigan''s hands-free law (effective June 30, 2023) prohibits all drivers from holding or manually using a cell phone or other mobile electronic device while operating a vehicle, including at a stop sign or red light. Level 1 and Level 2 GDL drivers are additionally prohibited from using a cell phone at all while driving (handheld or hands-free), with limited emergency exceptions.","notes":"Michigan uses a three-step Graduated Driver Licensing (GDL) program: Level 1 (Learner''s/Temporary Instruction Permit), Level 2 (Intermediate License), and Level 3 (Full License). Segment 1 driver education (24 hours classroom + 6 hours BTW + 4 hours observation) must be completed before testing for a Level 1 permit at age 14 years 9 months. After holding the Level 1 for at least 3 months and logging at least 30 of the required 50 supervised practice hours (10 at night), the teen must complete Segment 2 (6 hours classroom). After holding Level 1 for at least 6 months with no moving violations or at-fault crashes in the prior 90 days, and completing 50 total supervised hours (10 night), the teen may take the road skills test for a Level 2 license at age 16. Level 3 (full license) is granted at age 17 after holding Level 2 for at least 6 months with a clean record.","needsReview":["permitCredentialName phrasing — verify official SOS terminology (''TIP'' vs ''Level 1 License'')","permitCredentialDeliveryMode — confirm whether MI accepts electronic submission of driver-ed completion certificates from providers or still requires paper certificates","requiredBtwHours — Segment 1 BTW is 6 hours; Segment 2 adds classroom only (no additional BTW required); confirm whether the 6 figure is what the overlay expects","Observation hours (4 hours in Segment 1) not represented in schema — confirm if needed","Segment 2 classroom hours (6 hours, post-permit) not represented separately","minPermitAge encoded as 14.75 (14 years 9 months) — confirm decimal handling","passengerRestriction wording — confirm exact statutory exemptions","Cell phone rule — verify GDL-specific prohibition still extends to hands-free use under the 2023 law"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
