INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_how-to-get-a-permit-in-michigan_1', 'quiz_mi_how-to-get-a-permit-in-michigan', 'How many classroom and behind-the-wheel hours does Segment 1 require?', '["30 classroom + 8 BTW","24 classroom + 6 BTW (plus 4 observation)","20 classroom + 4 BTW","40 classroom + 10 BTW"]', 1, 'Segment 1 in Michigan consists of 24 hours of classroom instruction, 6 hours of behind-the-wheel driving with an instructor, and 4 hours of in-car observation.', 1
