INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_how-to-get-a-permit-in-michigan_2', 'quiz_mi_how-to-get-a-permit-in-michigan', 'While holding a Level 1 permit, who must be in the vehicle with you?', '["Any licensed driver age 18 or older in any seat","A parent, legal guardian, or designated licensed adult 21+ in the front passenger seat","Any adult, including unlicensed adults, anywhere in the vehicle","No one is required after the first 30 days"]', 1, 'A Level 1 driver must always be accompanied by a licensed parent, legal guardian, or a designated licensed adult who is at least 21 years old, seated in the front passenger seat.', 2
