INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_how-to-get-a-permit-in-michigan_3', 'quiz_mi_how-to-get-a-permit-in-michigan', 'Before taking Segment 2, you must have held your Level 1 for at least how long and logged how many supervised hours?', '["1 month and 10 hours","3 months and 30 hours (including 2 night hours)","6 months and 50 hours","No minimum — you can take Segment 2 immediately"]', 1, 'Michigan requires Level 1 drivers to hold the permit for at least 3 months and complete at least 30 of the 50 required supervised practice hours (including 2 night hours) before enrolling in Segment 2.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_how-to-get-a-permit-in-michigan_4', 'quiz_mi_how-to-get-a-permit-in-michigan', 'How many total hours of supervised driving practice must be logged before applying for a Level 2 license, and how many must be at night?', '["30 total / 5 at night","40 total / 8 at night","50 total / 10 at night","60 total / 12 at night"]', 2, 'Michigan requires 50 hours of parent-supervised driving practice, at least 10 of which must occur at night, before a teen can move from Level 1 to Level 2.', 4
