INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-gdl-restrictions-daily-life_0', 'quiz_mi_michigan-gdl-restrictions-daily-life', 'What are the hours of Michigan''s Level 2 nighttime driving restriction?', '["9 p.m. to 6 a.m.","10 p.m. to 5 a.m.","11 p.m. to 4 a.m.","Midnight to 6 a.m."]', 1, 'Level 2 drivers in Michigan may not drive between 10:00 p.m. and 5:00 a.m. unless a specific exception (work, school/religious activity, accompanied by an adult 21+, or emergency) applies.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-gdl-restrictions-daily-life_1', 'quiz_mi_michigan-gdl-restrictions-daily-life', 'How many passengers under age 21 may a Level 2 driver have in the vehicle (outside of exceptions)?', '["None — no passengers under 21 allowed at all","No more than one","No more than two","No limit"]', 1, 'A Level 2 driver may carry no more than one passenger under age 21 unless the additional passengers are immediate family, the trip is to or from school or a school event, or a licensed adult 21+ is in the vehicle.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-gdl-restrictions-daily-life_2', 'quiz_mi_michigan-gdl-restrictions-daily-life', 'Which of the following is NOT a valid exception to the Level 2 nighttime restriction?', '["Driving to or from work","Driving to a friend''s house to hang out","Driving to or from a school-sponsored activity","Driving with a parent in the front passenger seat"]', 1, 'Social trips to a friend''s house are not an exception to the nighttime curfew. Only work, school/civic/religious activities, an accompanying adult 21+, or a genuine emergency qualify.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-gdl-restrictions-daily-life_3', 'quiz_mi_michigan-gdl-restrictions-daily-life', 'Under Michigan''s GDL rules, a Level 1 or Level 2 driver may use a cell phone while driving only:', '["In hands-free mode at any time","Only when stopped at a red light","Only to call 911 in an emergency","Whenever the driver is alone in the car"]', 2, 'GDL drivers in Michigan are prohibited from using a cell phone while driving — handheld or hands-free — except to contact emergency services. The 2023 hands-free law adds a no-handheld rule for all drivers regardless of age.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-gdl-restrictions-daily-life_4', 'quiz_mi_michigan-gdl-restrictions-daily-life', 'What is one likely consequence of being cited for a Level 2 restriction violation?', '["Immediate revocation of the driver''s permit for one year","A civil infraction on the record, possible reset of the 90-day clean record requirement for Level 3, and likely higher insurance","Mandatory re-enrollment in Segment 1 driver education","No consequences if it is a first offense"]', 1, 'GDL restriction violations are civil infractions that appear on the driving record. They can delay advancement to Level 3 by resetting the clean-record clock, trigger a parent notification letter, and raise insurance premiums.', 4
);
INSERT OR REPLACE INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_mi_michigan-specific-rules-and-quirks', 'module_mi_overlay', 'michigan-specific-rules-and-quirks', 'Michigan-Specific Rules and Quirks: Hands-Free, Michigan Lefts, and Move Over', '## Michigan''s 2023 Hands-Free Law

On **June 30, 2023**, Michigan became a hands-free state. Under MCL 257.602b, **no driver of any age** may **hold or manually use** a cell phone or other mobile electronic device while operating a vehicle on a Michigan road — including when **stopped at a red light or stop sign**.

Prohibited acts include:

- Holding the phone in your hand or against your body.
- Sending, reading, or typing a text, email, or social media post.
- Watching, recording, or sending a video.
- Dialing or browsing manually.

Allowed (for adults): voice-activated calls and commands, one-touch activation, hands-free navigation, and use of integrated dashboard systems. **GDL Level 1 and Level 2 drivers face a stricter rule — no phone use at all, even hands-free**, except for emergencies.

Penalties escalate with repeat offenses and double if the violation occurs in a work zone or school zone, or contributes to a crash.

## The Michigan Left (Indirect Left Turn)

Michigan is famous for the **"Michigan Left."** On many divided highways — especially in metro Detroit — you cannot turn left directly at an intersection. Instead:

1. **Go straight through the intersection.**
2. Drive a short distance to a **dedicated U-turn crossover** (a median opening with its own signal or yield).
3. **Make a U-turn**, then drive back to the original intersection and **turn right**.

It feels strange the first time, but Michigan Lefts reduce left-turn crashes (the most dangerous intersection movement) and improve traffic flow. Watch for **"All Turns from Right Lane"** and **"No Left Turn"** signs.

## The Move Over Law

Michigan''s Move Over Law (Emergency Vehicle Caution Law) requires drivers approaching a **stationary authorized vehicle with flashing lights** — police, fire, EMS, tow trucks, road service, MDOT and utility vehicles, garbage trucks, mail carriers — to:

- **Move over one lane** away from the stopped vehicle if it is safe to do so, or
- **Slow down to at least 10 mph below the posted speed limit** if moving over is not possible.

Violations are civil infractions; if the violation causes injury or death to a responder, criminal penalties apply.

## Seat Belts and Child Restraints

- **Seat belts**: Required for the driver and **all front-seat passengers**, and for **all passengers under 16** regardless of seating position. Michigan is a **primary enforcement** state — police can stop and ticket you for a belt violation alone.
- **Child car seats**: Required for children **under age 4** (rear seat if available) and **booster seats until age 8 or 4''9" tall**, whichever comes first.

## Headlights, Wipers, and Weather

Michigan law requires **headlights on whenever windshield wipers are in continuous use** due to rain, snow, fog, or other weather. Daytime running lights alone do **not** satisfy this rule — your taillights must also be on. Given Michigan''s lake-effect snow and frequent precipitation, this rule comes up often.

## Speed Limits and Freeway Quirks

- Maximum freeway speed limit is **75 mph** on certain rural interstates and **70 mph** on most other freeways. Urban freeway limits typically range from **55 to 70 mph**.
- Some Michigan freeways post a **separate truck speed limit** (often 65 mph) lower than the car limit.
- **Right turn on red** is allowed after a complete stop unless a sign prohibits it.

## Deer

Michigan averages roughly **50,000 reported deer-vehicle crashes per year**, peaking in October and November (rut season) at dawn and dusk. If a deer is unavoidable, **brake firmly, stay in your lane, and do not swerve** — swerving into oncoming traffic or off the road causes far more serious injuries than the deer strike itself. Report any deer-vehicle crash with injury or significant damage to police.

## Winter Driving

Lake-effect snow, black ice, and rapid weather changes are routine in Michigan. Key habits:

- Clear **all** snow from the roof, hood, lights, and windows before driving — failing to do so can result in a citation if snow flies off and obstructs another driver.
- Increase following distance to **at least 6 seconds** on snow or ice.
- Know that **bridges and overpasses freeze first**.
', 30, 2
);
INSERT OR REPLACE INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_mi_michigan-specific-rules-and-quirks', 'lesson_mi_michigan-specific-rules-and-quirks', 'Michigan-Specific Rules and Quirks', 80, 1
