INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-specific-rules-and-quirks_0', 'quiz_mi_michigan-specific-rules-and-quirks', 'Under Michigan''s 2023 hands-free law, which of the following is true for an adult driver?', '["You may hold the phone as long as you are stopped at a red light","You may not hold or manually use a phone while operating the vehicle, including at red lights and stop signs","You may text as long as the message is shorter than 10 words","The law only applies to drivers under age 21"]', 1, 'Michigan''s hands-free law prohibits all drivers from holding or manually using a mobile device while operating a vehicle, including when stopped at a red light or stop sign. Voice-activated and one-touch use is permitted for adults; GDL drivers face stricter rules.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-specific-rules-and-quirks_1', 'quiz_mi_michigan-specific-rules-and-quirks', 'What is a ''Michigan Left''?', '["A left turn made from the rightmost lane at an intersection","Going straight through the intersection, making a U-turn at a designated crossover, then turning right","A protected left turn signal phase","A left turn made only during off-peak hours"]', 1, 'A Michigan Left replaces a direct left turn on a divided highway: drivers proceed through the intersection, make a U-turn at a dedicated median crossover, and then turn right at the original intersection.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-specific-rules-and-quirks_2', 'quiz_mi_michigan-specific-rules-and-quirks', 'Under Michigan''s Move Over Law, what must you do when approaching a stopped emergency or service vehicle with flashing lights?', '["Maintain your speed and stay in your lane","Move over one lane if safe, or slow to at least 10 mph below the posted speed limit","Stop completely until the vehicle leaves","Honk twice to acknowledge the vehicle"]', 1, 'Michigan''s Move Over Law requires drivers to move over one lane away from a stationary authorized vehicle displaying flashing lights when safe, or to slow to at least 10 mph below the speed limit if changing lanes is not possible.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-specific-rules-and-quirks_3', 'quiz_mi_michigan-specific-rules-and-quirks', 'Michigan law requires headlights to be on whenever:', '["It is between sunset and sunrise only","Windshield wipers are in continuous use due to weather","You are driving faster than 45 mph","You are on a freeway, regardless of conditions"]', 1, 'Michigan requires headlights (not just daytime running lights) to be on whenever windshield wipers are in continuous use due to rain, snow, fog, or other weather conditions, so taillights are also illuminated for visibility.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mi_michigan-specific-rules-and-quirks_4', 'quiz_mi_michigan-specific-rules-and-quirks', 'If a deer suddenly appears in your lane and a collision seems unavoidable, what is the recommended response?', '["Swerve sharply into the oncoming lane to avoid the deer","Accelerate to clear the deer''s path","Brake firmly, stay in your lane, and do not swerve","Close your eyes and hold the wheel straight"]', 2, 'Brake firmly and stay in your lane. Swerving — especially into oncoming traffic, trees, or ditches — causes far more serious crashes than hitting the deer. Michigan averages roughly 50,000 deer-vehicle crashes per year, peaking at dawn and dusk in fall.', 4
);

