INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_mn_teen_1_0_0', 'rp_mn_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Blue Card","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-MN","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Minnesota Department of Public Safety - Driver and Vehicle Services (DVS)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"For the first six months of provisional licensure, no driving between midnight and 5:00 a.m. unless accompanied by a licensed driver age 25+, driving to/from work, or driving for an employer.","passengerRestriction":"During the first six months of provisional licensure, no more than one passenger under age 20 (excluding immediate family). During the second six months, no more than three passengers under age 20 (excluding immediate family).","cellPhoneRule":"Drivers under 18 with a permit or provisional license may not use a cell phone (handheld or hands-free) while driving, except to call 911. Minnesota''s Hands-Free Law also prohibits all drivers from holding a phone while operating a vehicle.","notes":"Minnesota uses a three-stage Graduated Driver Licensing (GDL) system: Instruction Permit, Provisional License (age 16-18), and Full License (age 18+). The ''Blue Card'' is the supplemental permit-eligibility certificate issued by the driver education provider after the student completes 30 hours of classroom instruction; it is required (along with parental enrollment in the supervised driving log program) before the student can take the DVS knowledge test for the instruction permit. Teen students must complete 6 hours of behind-the-wheel instruction with a licensed instructor and log 50 hours of supervised driving (15 of which must be at night) before the road test. Parents must complete a free 90-minute online supplemental parental awareness course as part of the GDL process.","needsReview":["Exact current fee amounts for the knowledge test, permit, and road test (these change periodically).","Whether the parental awareness course is still 90 minutes and whether it is mandatory for all teens (rules updated in recent years).","Exact text of the night driving exception list - verify against current Minn. Stat. 171.055.","Whether Blue Card delivery is still strictly manual (paper) or whether DVS now accepts electronic submission from approved schools."]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
