INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-blue-card-permit-process_0', 'quiz_mn_mn-blue-card-permit-process', 'What is the ''Blue Card'' in Minnesota?', '["A driver license issued to drivers under 18","A classroom completion certificate from your driver education school that allows you to take the DVS knowledge test","A permit issued directly by DVS without any classroom training","A parental consent form filed with the courts"]', 1, 'The Blue Card is the Driver Education Classroom Completion Certificate issued by your driver education provider after you complete 30 hours of classroom instruction. It is required by DVS before you can take the knowledge test.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-blue-card-permit-process_1', 'quiz_mn_mn-blue-card-permit-process', 'What is the minimum age to hold a Minnesota instruction permit?', '["14 years old","14 years, 6 months old","15 years old","16 years old"]', 2, 'You must be at least 15 years old to hold a Minnesota instruction permit. You may begin classroom driver education before turning 15, but cannot take the DVS knowledge test until your 15th birthday.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-blue-card-permit-process_2', 'quiz_mn_mn-blue-card-permit-process', 'How many hours of classroom driver education are required in Minnesota?', '["20 hours","25 hours","30 hours","40 hours"]', 2, 'Minnesota requires 30 hours of classroom driver education from a state-approved provider before a Blue Card can be issued. There is no test-out option.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-blue-card-permit-process_3', 'quiz_mn_mn-blue-card-permit-process', 'What must a parent or guardian do before the Blue Card can be issued?', '["Pass the DVS knowledge test on the teen''s behalf","Complete a free online supplemental parental awareness course (about 90 minutes)","Pay the road test fee in advance","Sign a notarized affidavit at the courthouse"]', 1, 'A parent or legal guardian must complete a free online supplemental parental awareness course offered by the Department of Public Safety. The completion certificate is part of the permit application packet.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-blue-card-permit-process_4', 'quiz_mn_mn-blue-card-permit-process', 'After receiving the instruction permit, how long must you hold it before applying for a provisional license?', '["3 months","6 months, violation-free for the last 6 months","9 months","12 months"]', 1, 'Minnesota requires you to hold the instruction permit for at least 6 months, and the last 6 months must be violation-free, before you can apply for a provisional license.', 4
