INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-rules-and-quirks_0', 'quiz_mn_mn-rules-and-quirks', 'Under Minnesota''s Ted Foss Move Over Law, what must you do when approaching a stopped emergency vehicle with flashing lights on a road with two or more lanes in your direction?', '["Maintain the posted speed limit and stay in your lane","Move over one full lane away if safe; if not safe, slow down to a safe and reasonable speed","Come to a complete stop until the emergency vehicle leaves","Honk to acknowledge the responder and continue at full speed"]', 1, 'The Ted Foss Law requires drivers to move over one full lane when safe, or slow down significantly if moving over is not possible, when approaching any stopped emergency, tow, maintenance, construction, or utility vehicle with flashing lights.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-rules-and-quirks_1', 'quiz_mn_mn-rules-and-quirks', 'When are Minnesota drivers required to turn on their headlights?', '["Only between sunset and sunrise","Anytime windshield wipers are in continuous use due to weather conditions","Only on interstate highways","Only when visibility drops below 100 feet"]', 1, 'Minnesota law requires headlights to be on anytime windshield wipers are in continuous use because of weather. Daytime running lights alone do not satisfy this requirement because they do not illuminate taillights.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-rules-and-quirks_2', 'quiz_mn_mn-rules-and-quirks', 'When entering a Minnesota roundabout, you must:', '["Stop completely, then proceed","Yield to traffic already in the roundabout (traffic on your left)","Use your left turn signal to enter","Yield only to vehicles entering from your right"]', 1, 'Drivers approaching a roundabout must yield to traffic already circulating inside it - that traffic will be coming from your left. Do not stop unnecessarily; just yield and merge when there is a safe gap.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-rules-and-quirks_3', 'quiz_mn_mn-rules-and-quirks', 'On a two-lane undivided road, what must you do when a school bus extends its stop arm with red lights flashing?', '["Only vehicles behind the bus must stop; oncoming traffic may proceed slowly","All traffic in both directions must stop and remain stopped until the arm retracts and lights stop flashing","Slow to 20 mph and pass with caution","Stop only if children are visible crossing the road"]', 1, 'On a two-lane or any undivided road, traffic in both directions must stop for a school bus with its stop arm out and red lights flashing. On a divided highway with a physical median, only traffic following the bus must stop.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mn_mn-rules-and-quirks_4', 'quiz_mn_mn-rules-and-quirks', 'Under Minnesota''s ''Not a Drop'' law, what is the legal blood alcohol limit for drivers under 21?', '["0.08%, the same as adult drivers","0.04%, the commercial driver limit","0.02%","Any detectable amount of alcohol is a violation"]', 3, 'Minnesota''s ''Not a Drop'' law makes any detectable amount of alcohol in a driver under 21 a DWI offense, resulting in license suspension. There is no ''safe'' amount for an underage driver.', 4
);

