INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_mo_teen_1_0_0', 'rp_mo_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":0,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":0,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":40,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-MO","minPermitAge":15,"classroomHoursCompleted":{"gte":0}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Missouri Department of Revenue (DOR) - Driver License Bureau","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Intermediate license holders (under 18) may not drive between 1:00 a.m. and 5:00 a.m. except to/from a school activity, job, or emergency.","passengerRestriction":"During the first 6 months of an intermediate license, no more than one passenger under age 19 who is not an immediate family member. After 6 months, no more than three passengers under age 19 who are not immediate family.","cellPhoneRule":"As of August 2023, the Siddens Bening Hands Free Law prohibits all drivers from physically holding or using a cell phone while driving. For drivers under 21, any use of a hand-held electronic communication device while driving is prohibited.","notes":"Missouri does not mandate a state-required number of formal classroom or behind-the-wheel hours for the standard GDL pathway, but does require a parent/guardian-certified log of at least 40 hours of supervised driving (including a minimum of 10 hours at night) before applying for an intermediate license at 16. The instruction permit must be held for at least 6 months. Missouri uses a three-stage GDL: Instruction Permit (15), Intermediate License (16), Full License (18). Applicants must pass a written, vision, and road sign test for the permit, and a driving skills test for the intermediate license.","needsReview":["Exact current fee amounts for permit and intermediate license","Whether the supervised driving log form (DOR-100) has been renumbered recently","Confirm cell phone law enforcement details (primary vs secondary) for adult drivers","Verify any 2025-2026 legislative updates to GDL requirements"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
