INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mo_missouri-gdl-restrictions-daily-life_2', 'quiz_mo_missouri-gdl-restrictions-daily-life', 'Under Missouri''s Siddens Bening Hands Free Law, what is the rule for drivers under 21?', '["Hands-free calls are allowed without restriction","Texting is allowed if stopped at a red light","Any use of a hand-held electronic communication device while driving is prohibited","There are no special restrictions beyond the general adult rule"]', 2, 'Drivers under 21 face the strictest rule: no hand-held device use while driving, period. Adults are also banned from holding phones, but the under-21 rule is broader.', 2
