INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mo_missouri-specific-rules-and-quirks_0', 'quiz_mo_missouri-specific-rules-and-quirks', 'Under Missouri''s "Dead Red Law," what may you do at a traffic signal that fails to detect your vehicle?', '["Immediately drive through the red light","Turn around and find another route - it is never legal to proceed","Proceed cautiously through the red after waiting a reasonable amount of time and confirming it is safe","Honk repeatedly until another driver triggers the sensor"]', 2, 'The Dead Red Law allows you to proceed through a malfunctioning red light after waiting a reasonable time (such as a full signal cycle) and confirming it is safe.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mo_missouri-specific-rules-and-quirks_1', 'quiz_mo_missouri-specific-rules-and-quirks', 'When must you stop for a school bus with its red lights flashing and stop-arm extended on a TWO-LANE road in Missouri?', '["Only traffic behind the bus must stop","Only traffic in the oncoming lane must stop","All traffic in both directions must stop","Only if children are visibly crossing"]', 2, 'On a two-lane road, all traffic in both directions must stop. Only on a divided highway with a physical median/barrier may oncoming traffic proceed.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mo_missouri-specific-rules-and-quirks_2', 'quiz_mo_missouri-specific-rules-and-quirks', 'If a deer enters the road in front of you, what is the recommended response?', '["Swerve sharply to avoid contact","Speed up to pass before the deer reaches the road","Brake firmly and stay in your lane - do not swerve","Honk and maintain your speed"]', 2, 'Braking firmly without swerving is recommended. Swerving often causes loss-of-control crashes that are worse than striking the deer.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mo_missouri-specific-rules-and-quirks_3', 'quiz_mo_missouri-specific-rules-and-quirks', 'What does Missouri''s Move Over law require when you approach a stopped emergency vehicle with flashing lights?', '["Stop completely until the emergency vehicle leaves","Change lanes away from the vehicle if safe; otherwise slow down and proceed with caution","Maintain your speed and stay in your lane","Honk to alert the emergency personnel"]', 1, 'Missouri''s Move Over law requires you to change lanes away from the stopped emergency vehicle when safe; if you cannot change lanes, slow down and proceed with caution.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mo_missouri-specific-rules-and-quirks_4', 'quiz_mo_missouri-specific-rules-and-quirks', 'What do Missouri''s lettered routes (such as Route Z or Route AA) typically indicate?', '["Interstate bypass routes","State-maintained secondary roads, often rural and lightly trafficked","Toll roads","Routes restricted to commercial vehicles"]', 1, 'Lettered routes are Missouri''s state-maintained supplemental/secondary roads, common in rural areas and often narrow or winding.', 4
);

