INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ms_mississippi-specific-rules-and-quirks_3', 'quiz_ms_mississippi-specific-rules-and-quirks', 'What happens if you refuse a breath, blood, or urine test under Mississippi''s implied consent law (first refusal)?', '["Nothing - it is your legal right","A small fine only","Automatic license suspension (typically 90 days)","Immediate jail time without trial"]', 2, 'Refusing the test under implied consent triggers an automatic license suspension - around 90 days for a first refusal.', 3
