INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ms_mississippi-specific-rules-and-quirks_4', 'quiz_ms_mississippi-specific-rules-and-quirks', 'Which Mississippi rule about funeral processions is correct?', '["Other drivers may pass the procession freely on a multilane road","Other drivers must yield the right of way and not cut into the procession","The procession must stop at every red light individually","Funeral processions do not have any special legal status in Mississippi"]', 1, 'Mississippi law gives funeral processions the right of way; other drivers must yield and may not cut into or pass the line of vehicles in the procession.', 4
