INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_mt_teen_1_0_0', 'rp_mt_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Traffic Education Learner License","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-MT","minPermitAge":14.5,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Montana Motor Vehicle Division (MVD)","minPermitAge":14.5,"minLicenseAge":15,"minPermitDurationMonths":6,"nighttimeRestriction":"First six months of restricted license: no driving between 11:00 p.m. and 5:00 a.m. unless accompanied by a licensed parent/guardian or driving to/from work, school, or a school activity.","passengerRestriction":"First six months of restricted license: no more than one passenger under age 18 who is not an immediate family member. Second six months: no more than three passengers under 18 who are not immediate family members.","cellPhoneRule":"Montana does not have a statewide handheld cell phone or texting ban, but many cities (including Billings, Bozeman, Missoula, Helena, Whitefish, and Butte-Silver Bow) have local ordinances banning handheld use and/or texting while driving. Drivers with a restricted license should avoid all cell phone use while operating a vehicle.","notes":"Montana uses a Graduated Driver Licensing (GDL) system administered by the MVD (a division of the Department of Justice). Teens who complete an approved Traffic Education course may begin with a Traffic Education Learner License (TELL) at 14 years 6 months; teens who do not take traffic education must wait until age 16 for a regular learner license. After holding a permit for at least 6 months with no qualifying violations and completing 50 hours of supervised driving (10 at night), teens become eligible for a restricted (provisional) license at 15. The full unrestricted license is available at 16 (one year after the restricted license or at age 18, whichever comes first). Montana''s combination of low minimum ages and largely rural roads makes the GDL passenger and nighttime restrictions especially important.","needsReview":["Exact required classroom hours (commonly cited as 30 but verify current OPI Traffic Education standards)","Exact BTW hour requirement (commonly 6 hours, sometimes paired with 6 hours of observation)","Whether the 50-hour supervised practice requirement includes a specific night-driving subtotal (commonly cited as 10 hours)","Current official name of the permit credential (''Traffic Education Learner License'' vs ''Learner License'')","Whether MVD accepts electronic submission of the Traffic Education completion certificate or still requires a paper/in-person handoff","Exact statutory citation for nighttime and passenger restrictions (MCA 61-5-133 and related sections)"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
