INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mt_how-to-get-a-montana-permit_3', 'quiz_mt_how-to-get-a-montana-permit', 'Which of these is NOT a required document at the MVD when applying for a learner license?', '["Certified birth certificate or U.S. passport","Two proofs of Montana residency","A signed lease in the teen''s own name","A parent or guardian''s in-person signature"]', 2, 'The lease can be in the parent''s name; the teen does not need a lease in their own name. The other items are required.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mt_how-to-get-a-montana-permit_4', 'quiz_mt_how-to-get-a-montana-permit', 'Minimum length of time you must hold a Montana learner license with a clean record before becoming eligible for the next license stage:', '["30 days","3 months","6 months","12 months"]', 2, 'Montana requires the learner license to be held for at least 6 months with no qualifying alcohol/drug or major traffic violations before moving on to the restricted license.', 4
