INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mt_mt-gdl-restrictions-daily-life_4', 'quiz_mt_mt-gdl-restrictions-daily-life', 'What is the most likely consequence of a Montana GDL violation during the restricted-license period?', '["Nothing — GDL rules are advisory","A fine only, with no license impact","A citation, a fine, and a restart of the six-month restriction clock","Immediate permanent revocation of the license"]', 2, 'A GDL violation typically results in a citation, fine, and a reset of the six-month restriction window. Repeated violations can extend restrictions until age 18.', 4
