INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mt_montana-specific-driving-rules-and-quirks_1', 'quiz_mt_montana-specific-driving-rules-and-quirks', 'Under Montana''s basic speed rule, you can be cited for driving too fast for conditions when:', '["Only when you exceed the posted speed limit","Only on interstates","When your speed is unsafe for the weather, road, or visibility — even if below the posted limit","Only when an officer measures you with radar"]', 2, 'The basic rule requires a reasonable and prudent speed for conditions. You can be cited even at speeds well below the posted limit.', 1
