INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mt_montana-specific-driving-rules-and-quirks_2', 'quiz_mt_montana-specific-driving-rules-and-quirks', 'In Montana open-range country, if you hit livestock on the road, who is generally financially responsible for the animal?', '["The rancher, always","The state of Montana","The driver (or the driver''s insurance)","No one — the loss is uninsurable"]', 2, 'In open-range areas livestock may lawfully be on the road; the driver is generally responsible for the value of an animal they hit.', 2
