INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mt_montana-specific-driving-rules-and-quirks_3', 'quiz_mt_montana-specific-driving-rules-and-quirks', 'The safest reaction when a deer suddenly appears in your lane on a Montana highway is to:', '["Swerve hard into the opposite lane","Swerve hard onto the shoulder","Brake firmly in a straight line and stay in your lane","Accelerate to get past it"]', 2, 'Braking in a straight line is far safer than swerving, which often causes rollovers or head-on collisions that are worse than the animal strike itself.', 3
