INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_mt_montana-specific-driving-rules-and-quirks_4', 'quiz_mt_montana-specific-driving-rules-and-quirks', 'Which statement about cell phone use while driving in Montana is correct?', '["Montana bans handheld phone use statewide for all drivers","Montana bans only texting statewide; calls are allowed","There is no statewide ban, but many cities ban handheld use and/or texting","Cell phone use is fully legal everywhere in Montana with no local restrictions"]', 2, 'Montana has no statewide handheld or texting ban, but cities like Billings, Bozeman, Missoula, Helena, and Whitefish have local ordinances. Restricted-license holders should avoid all handheld use.', 4
