INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_nc_teen_1_0_0', 'rp_nc_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Limited Learner Permit (Level 1)","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":60,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-NC","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"North Carolina Division of Motor Vehicles (NCDMV)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":12,"nighttimeRestriction":"Level 1 (Limited Learner Permit): may only drive between 5:00 a.m. and 9:00 p.m. for the first 6 months; after 6 months may drive any time with supervising driver. Level 2 (Limited Provisional License): may not drive between 9:00 p.m. and 5:00 a.m. except when driving to/from work, volunteer fire/rescue/EMS service, or with a supervising driver.","passengerRestriction":"Level 1: only the supervising driver in the front seat; other passengers limited to immediate family members or fellow students in a driver education program. Level 2: limited to no more than one passenger under age 21 who is not a member of the driver''s immediate family, unless a parent or supervising driver is in the front seat.","cellPhoneRule":"Drivers under 18 are prohibited from using any mobile phone or other wireless communications device while driving (including hands-free), except to call a parent, guardian, or spouse, or in an emergency to call 911. Texting while driving is illegal for all drivers regardless of age.","notes":"North Carolina has a three-stage Graduated Driver Licensing (GDL) program: Level 1 Limited Learner Permit (age 15), Level 2 Limited Provisional License (age 16), and Level 3 Full Provisional License (age 16.5). Driver education (classroom + BTW) is required for any applicant under 18 and is provided free of charge through public high schools, though many districts contract with private providers. A signed Driving Eligibility Certificate (DEC) is required to obtain a permit or license under age 18, certifying enrollment and satisfactory academic progress in school (the ''Lose Control, Lose Your License'' law).","needsReview":["Exact wording of Level 1 nighttime hours (5 a.m. to 9 p.m. cutoff) — verify against current NCDMV publication","Whether NC still requires 60 supervised practice hours including 10 at night, or if that figure has changed","Current DEC (Driving Eligibility Certificate) issuance process and whether any 2024-2026 statutory changes apply","Whether private driver education providers must be approved by NCDPI or NCDMV"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
