INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_how-to-get-a-permit-in-north-carolina_0', 'quiz_nc_how-to-get-a-permit-in-north-carolina', 'What is the minimum age to apply for a North Carolina Limited Learner Permit (Level 1)?', '["14 years old","14 years and 6 months","15 years old","16 years old"]', 2, 'North Carolina allows teens to apply for a Level 1 Limited Learner Permit beginning on their 15th birthday, provided they have completed driver education and have a valid DEC.', 0
