INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_how-to-get-a-permit-in-north-carolina_1', 'quiz_nc_how-to-get-a-permit-in-north-carolina', 'How many hours of classroom and behind-the-wheel instruction does NC driver education require?', '["20 classroom + 4 BTW","30 classroom + 6 BTW","40 classroom + 8 BTW","30 classroom + 10 BTW"]', 1, 'NC''s standard driver education course requires 30 hours of classroom instruction plus 6 hours of behind-the-wheel instruction with a certified instructor.', 1
