INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_how-to-get-a-permit-in-north-carolina_2', 'quiz_nc_how-to-get-a-permit-in-north-carolina', 'What is a Driving Eligibility Certificate (DEC) and how long is it valid?', '["A police clearance valid for 90 days","A school-issued certificate of enrollment and academic progress, valid for 30 days","A medical waiver valid for 1 year","A parental consent form valid indefinitely"]', 1, 'The DEC is signed by a school official under NC''s ''Lose Control, Lose Your License'' law to confirm enrollment and academic progress. It is valid for 30 days from issuance.', 2
