INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_how-to-get-a-permit-in-north-carolina_3', 'quiz_nc_how-to-get-a-permit-in-north-carolina', 'During the first 6 months of holding a Level 1 permit, when may the teen driver legally drive?', '["Any time, no restriction","Only between 5:00 a.m. and 9:00 p.m.","Only between 6:00 a.m. and 10:00 p.m.","Only during daylight hours"]', 1, 'For the first 6 months on a Limited Learner Permit, NC restricts driving to the window between 5:00 a.m. and 9:00 p.m., even with a supervising driver.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_how-to-get-a-permit-in-north-carolina_4', 'quiz_nc_how-to-get-a-permit-in-north-carolina', 'How many supervised practice hours must a Level 1 permit holder log before moving to Level 2?', '["30 hours, including 5 at night","40 hours, including 10 at night","60 hours, including 10 at night","100 hours, including 20 at night"]', 2, 'NC requires at least 60 hours of supervised driving practice, of which at least 10 must be at night, before a Level 1 driver can advance to the Level 2 Limited Provisional License.', 4
