INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_nc-gdl-restrictions-in-daily-life_4', 'quiz_nc_nc-gdl-restrictions-in-daily-life', 'Which of the following Level 1 supervising-driver rules is correct?', '["The supervisor can sit anywhere in the car","The supervisor must be at least 18 and licensed","The supervisor must be at least 21, licensed for 5+ years, and in the front passenger seat","The supervisor only needs to be present at night"]', 2, 'On Level 1, the supervising driver must be 21 or older, hold a valid license that they''ve had for at least 5 years, and remain in the front passenger seat at all times while the permit holder drives.', 4
