INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_nc-specific-rules-and-quirks_1', 'quiz_nc_nc-specific-rules-and-quirks', 'Which mobile phone use is allowed for a 17-year-old NC driver behind the wheel?', '["Hands-free Bluetooth calls to friends","Texting at a red light","Calling a parent or 911 in an emergency","Streaming music through the phone speaker"]', 2, 'NC bans all mobile phone use (including hands-free) by drivers under 18 except for calls to a parent, legal guardian, or spouse, or 911 emergency calls.', 1
