INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_nc-specific-rules-and-quirks_2', 'quiz_nc_nc-specific-rules-and-quirks', 'When does NC law require your headlights (not parking lights) to be on?', '["Only between sunset and sunrise","Whenever your windshield wipers are operating continuously due to weather","Only in fog","Only on highways"]', 1, 'Under § 20-129, if your wipers are running continuously because of rain, snow, sleet, or fog, your headlights must be on — daytime running lights do not satisfy this because taillights must also be lit.', 2
