INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_nc-specific-rules-and-quirks_3', 'quiz_nc_nc-specific-rules-and-quirks', 'On a two-lane road with no median, what must oncoming traffic do when a school bus stops with its stop arm extended?', '["Slow to 25 mph and proceed with caution","Continue normally, only the bus''s lane must stop","Come to a complete stop until the stop arm is retracted","Honk to alert the bus driver"]', 2, 'On roads without a physical median, all traffic in both directions must come to a complete stop. Hannah''s Law adds enhanced penalties — including potential felony charges — for passing a stopped school bus.', 3
