INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nc_nc-specific-rules-and-quirks_4', 'quiz_nc_nc-specific-rules-and-quirks', 'What is the BAC limit for an 18-year-old NC driver?', '["0.08%","0.05%","0.02%","Any detectable alcohol (above 0.00) is a per se DWI"]', 3, 'North Carolina has a zero-tolerance law for drivers under 21: any detectable alcohol (BAC greater than 0.00) is a per se DWI, with automatic one-year license revocation and no limited driving privilege.', 4
