INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nd_how-to-get-a-permit-in-north-dakota_1', 'quiz_nd_how-to-get-a-permit-in-north-dakota', 'If you are under 16, what driver education must be completed before licensure in North Dakota?', '["No formal education required","An approved course with at least 30 hours classroom and 6 hours behind-the-wheel","Only an online theory course","A 10-hour weekend seminar"]', 1, 'Applicants under 16 must complete a state-approved driver education course that includes a minimum of 30 classroom hours and 6 hours of behind-the-wheel training.', 1
