INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nd_how-to-get-a-permit-in-north-dakota_2', 'quiz_nd_how-to-get-a-permit-in-north-dakota', 'Who must be in the vehicle when you drive on a North Dakota instruction permit?', '["Any licensed driver age 16 or older","A licensed driver age 18 or older in the front passenger seat","A parent only","A driving instructor only"]', 1, 'Permit holders must be accompanied by a licensed driver who is at least 18 years old and seated next to them in the front seat.', 2
