INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nd_how-to-get-a-permit-in-north-dakota_4', 'quiz_nd_how-to-get-a-permit-in-north-dakota', 'Which document is required at the license site for an applicant under 18?', '["A signed school report card","A parent or legal guardian signature on the application","A notarized affidavit from a teacher","An employer verification letter"]', 1, 'Any applicant under 18 must have a parent or legal guardian present to sign the application, accepting responsibility for the minor''s driving.', 4
