  'q_nd_north-dakota-specific-rules-and-quirks_0', 'quiz_nd_north-dakota-specific-rules-and-quirks', 'What is the typical maximum speed limit on rural North Dakota interstates?', '["55 mph","65 mph","70 mph","75 mph"]', 3, 'Many rural North Dakota interstates are posted at 75 mph, though drivers must always reduce speed for conditions.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nd_north-dakota-specific-rules-and-quirks_1', 'quiz_nd_north-dakota-specific-rules-and-quirks', 'Under North Dakota''s Move Over Law, what must you do when approaching a stopped tow truck with flashing lights?', '["Maintain speed and stay in your lane","Move over one lane if safe, or slow to a safe speed","Stop completely until the tow truck leaves","Honk to alert the tow operator"]', 1, 'The Move Over Law requires drivers to vacate the lane adjacent to a stopped emergency, tow, or maintenance vehicle when safe, and to slow down if changing lanes is not possible.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nd_north-dakota-specific-rules-and-quirks_2', 'quiz_nd_north-dakota-specific-rules-and-quirks', 'What does the orange triangle on the back of a vehicle indicate?', '["Hazardous materials onboard","A Slow-Moving Vehicle that travels 25 mph or less","A learner driver","An out-of-state vehicle"]', 1, 'The orange Slow-Moving Vehicle (SMV) triangle identifies vehicles, often farm equipment, that travel at 25 mph or less.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nd_north-dakota-specific-rules-and-quirks_3', 'quiz_nd_north-dakota-specific-rules-and-quirks', 'If you become stranded during a North Dakota blizzard, what is the recommended action?', '["Walk to the nearest farmhouse","Stay with your vehicle and run the engine periodically for heat","Sleep in the trunk for insulation","Start a fire next to the vehicle"]', 1, 'Authorities recommend staying with the vehicle, which is easier for rescuers to find, and running the engine periodically while keeping the exhaust pipe clear of snow.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nd_north-dakota-specific-rules-and-quirks_4', 'quiz_nd_north-dakota-specific-rules-and-quirks', 'When must headlights be turned on in North Dakota beyond the standard nighttime hours?', '["Only during rain","Whenever visibility is less than 1,000 feet","Only on interstates","Only when other vehicles approach"]', 1, 'North Dakota law requires headlights any time visibility is less than 1,000 feet, in addition to the period from a half hour after sunset to a half hour before sunrise.', 4
);

