INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_ne_teen_1_0_0', 'rp_ne_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner''s Permit (LPD)","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-NE","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Nebraska Department of Motor Vehicles (DMV)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Provisional Operator''s Permit (POP) holders may not drive between midnight and 6:00 a.m. unless going to/from work or a school activity.","passengerRestriction":"During the first 6 months with a POP, the driver may not have more than one passenger under age 19 who is not an immediate family member.","cellPhoneRule":"Drivers under 18 are prohibited from using any handheld or hands-free wireless communication device while driving. Texting is banned for all drivers regardless of age.","notes":"Nebraska offers two paths to a full license: completing an approved driver education course (allows licensing at 16) or holding the LPE/LPD for the required period. The School Permit (SCP) is available at age 14 years 2 months to students in school districts of fewer than 5,000 residents who live more than 1.5 miles from school. Nebraska uses a tiered GDL with the Provisional Operator''s Permit (POP) issued at 16 before a full Class O Operator''s License is available.","needsReview":["Exact name ''Learner''s Permit (LPD)'' vs ''LPE'' - Nebraska uses LPE (Learner''s Permit for driver education students, age 15) and LPD (standard learner''s permit, age 15 with extra requirements). Confirm which to use as primary credential name.","Whether 30 classroom hours is the current state-mandated minimum for approved driver education courses (may be set by individual schools/approved providers rather than statute).","Confirm 6 hours BTW as the standard approved-course requirement.","Verify the exact 50-hour supervised practice requirement; Nebraska''s CDE (Certified Driver Education) requirements may differ from POP self-certification of practice hours.","Confirm minimum holding period of 6 months for POP applicants who did not complete driver education.","Exact School Permit (SCP) age threshold and district population limit (commonly cited as 14 years 2 months and districts under 5,000)."]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
