  'q_ne_ne-gdl-restrictions-daily-life_0', 'quiz_ne_ne-gdl-restrictions-daily-life', 'What are the nighttime driving hours restricted for Nebraska POP holders?', '["9 p.m. to 5 a.m.","10 p.m. to 6 a.m.","11 p.m. to 5 a.m.","Midnight to 6 a.m."]', 3, 'POP holders may not drive between midnight and 6:00 a.m. except for work, school activities, or emergencies.', 0
