INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_nh_teen_1_0_0', 'rp_nh_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Youth Operator License (no learner permit issued by the state)","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":10,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":40,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-NH","minPermitAge":15.5,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"New Hampshire Division of Motor Vehicles (NH DMV)","minPermitAge":15.5,"minLicenseAge":16,"minPermitDurationMonths":0,"nighttimeRestriction":"Drivers under 18 may not drive between 1:00 a.m. and 4:00 a.m. unless accompanied by a parent or guardian, or for employment, school, or emergency purposes.","passengerRestriction":"During the first 6 months after licensing, drivers under 18 may not transport more than one passenger under age 25 unless a licensed adult 25+ is in the vehicle, or passengers are immediate family.","cellPhoneRule":"All handheld electronic device use (calls, texting) is prohibited while driving for drivers under 18. New Hampshire also bans handheld phone use for all drivers.","notes":"New Hampshire is unusual: the state does NOT issue a traditional learner permit. Teens under 18 must complete a state-approved driver education course (30 hrs classroom, 10 hrs behind-the-wheel, 6 hrs observation) before they can be licensed. They practice driving under the supervision of a licensed driver 25+ using only their driver-education enrollment as authorization. After course completion and 40 hours of parent-supervised practice (10 at night), they may apply for a Youth Operator License at age 16. New Hampshire is one of the few states with no mandatory road test for adults 18+, but teen applicants must pass a road test administered by the DMV.","needsReview":["Exact passenger restriction wording and family exemption details","Whether the 1 a.m. to 4 a.m. curfew has been updated recently","Confirmation that NH still does not issue a learner permit document","Exact required observation hours (6) vs behind-the-wheel hours (10) split","Whether the 40-hour supervised practice requirement is statutory or recommended"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
