INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nh_nh-gdl-restrictions-daily-life_0', 'quiz_nh_nh-gdl-restrictions-daily-life', 'What hours does the NH nighttime driving curfew cover for drivers under 18?', '["10:00 p.m. to 5:00 a.m.","11:00 p.m. to 6:00 a.m.","1:00 a.m. to 4:00 a.m.","Midnight to 5:00 a.m."]', 2, 'The curfew runs from 1:00 a.m. to 4:00 a.m. Exceptions include work, school events, emergencies, or driving with a parent or guardian.', 0
