INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nh_nh-gdl-restrictions-daily-life_1', 'quiz_nh_nh-gdl-restrictions-daily-life', 'During the first 6 months of having a Youth Operator License, how many passengers under 25 may you transport without a 25+ adult in the car?', '["Zero","One","Two","Three"]', 1, 'You may have only one passenger under age 25, unless the additional passengers are immediate family or a licensed driver 25+ is also in the car.', 1
