INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_how-to-get-a-nj-permit_1', 'quiz_nj_how-to-get-a-nj-permit', 'What is the minimum holding period for a New Jersey learner''s permit before a road test can be scheduled?', '["3 months","6 months","9 months","12 months"]', 1, 'New Jersey requires permit holders to practice for at least 6 months before they are eligible to take the road test.', 1
