INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_how-to-get-a-nj-permit_2', 'quiz_nj_how-to-get-a-nj-permit', 'If you are 17 years old and want a New Jersey learner''s permit, where do you apply?', '["Only through a licensed driving school","Directly at an MVC licensing center (Examination Permit)","Through your local police department","Online through the NJ MVC website without an in-person visit"]', 1, 'At 17 or older, you can apply directly at an MVC licensing center for an Examination Permit and are not required to go through a driving school.', 2
