INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-gdl-daily-life-and-red-decal_1', 'quiz_nj_nj-gdl-daily-life-and-red-decal', 'What are the New Jersey GDL curfew hours?', '["10:00 p.m. to 5:00 a.m.","11:01 p.m. to 5:00 a.m.","Midnight to 6:00 a.m.","9:00 p.m. to 6:00 a.m."]', 1, 'GDL permit and probationary license holders may not drive between 11:01 p.m. and 5:00 a.m. unless they have documented employment or religious-observance exceptions.', 1
