INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-gdl-daily-life-and-red-decal_2', 'quiz_nj_nj-gdl-daily-life-and-red-decal', 'How many additional passengers may a New Jersey GDL driver under 21 carry, absent an exception?', '["No passengers at all","One additional passenger","Two additional passengers","Three additional passengers"]', 1, 'GDL drivers under 21 may carry only one additional passenger, except when a parent or guardian is in the front seat or when all passengers are the driver''s dependents.', 2
