INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-gdl-daily-life-and-red-decal_3', 'quiz_nj_nj-gdl-daily-life-and-red-decal', 'Which statement about cell phone use is true for New Jersey GDL drivers?', '["Hands-free calling is allowed","Texting is allowed at red lights","All cell phone use, handheld and hands-free, is prohibited except for true emergencies","Cell phone use is allowed on highways but not local roads"]', 2, 'Unlike fully licensed adult drivers, GDL drivers cannot use a cell phone in any mode — handheld or hands-free — except to contact emergency services.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-gdl-daily-life-and-red-decal_4', 'quiz_nj_nj-gdl-daily-life-and-red-decal', 'Kyleigh''s Law is named after a person who was a:', '["Driving instructor","Legislator who sponsored the bill","Teenage passenger who died in a crash","Police officer killed in the line of duty"]', 2, 'The law is named after Kyleigh D''Alessio, a 16-year-old passenger who died in a 2006 crash involving a teen driver.', 4
