INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-specific-rules-and-quirks_0', 'quiz_nj_nj-specific-rules-and-quirks', 'Which of the following is true about gasoline in New Jersey?', '["Self-service is required at all stations","Self-service is prohibited; an attendant must pump your gas","Self-service is allowed only between 6 a.m. and 10 p.m.","Self-service is allowed only for diesel fuel"]', 1, 'New Jersey is the only U.S. state where self-service gasoline is prohibited statewide — an attendant must pump your gas.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-specific-rules-and-quirks_1', 'quiz_nj_nj-specific-rules-and-quirks', 'At what age can a New Jersey driver receive an unrestricted (basic) driver''s license under the standard GDL pathway?', '["16","17","18","21"]', 2, 'At 17, drivers receive a probationary license with continued GDL restrictions. The unrestricted basic license is available at 18 after completing the probationary year without violations.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-specific-rules-and-quirks_2', 'quiz_nj_nj-specific-rules-and-quirks', 'What is a jughandle?', '["A type of parallel parking space","A right-side ramp used to make a left turn or U-turn on many New Jersey highways","A New Jersey-specific traffic signal","A special license plate frame"]', 1, 'A jughandle is a ramp on the right side of a highway that loops around to a traffic signal, allowing drivers to make left turns and U-turns without crossing from the left lane.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-specific-rules-and-quirks_3', 'quiz_nj_nj-specific-rules-and-quirks', 'When must New Jersey drivers turn on their headlights?', '["Only at night","Only in heavy rain or snow","Any time the windshield wipers are in use","Only when visibility is under 500 feet"]', 2, 'New Jersey''s ''wipers on, lights on'' law requires full headlights any time the windshield wipers are operating, including in light rain or snow.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_nj_nj-specific-rules-and-quirks_4', 'quiz_nj_nj-specific-rules-and-quirks', 'On an undivided two-lane road, what must you do when a school bus stops with red flashing lights and an extended stop arm?', '["Continue driving in the opposite lane at reduced speed","Stop only if you are behind the bus","All traffic in both directions must stop","Honk to alert other drivers and proceed slowly"]', 2, 'On an undivided road, traffic in both directions must stop. Only on divided highways with a physical barrier or median may traffic in the opposite direction proceed.', 4
);

