  'rpv_nm_teen_1_0_0', 'rp_nm_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Instructional Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":7,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-NM","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"New Mexico Motor Vehicle Division (MVD)","minPermitAge":15,"minLicenseAge":15.5,"minPermitDurationMonths":6,"nighttimeRestriction":"Provisional license holders may not drive between midnight and 5:00 a.m. unless accompanied by a licensed driver 21 or older, or for work, school, medical, or emergency reasons.","passengerRestriction":"Provisional license holders may not transport more than one passenger under 21 who is not an immediate family member.","cellPhoneRule":"Drivers under 18 are prohibited from any use of a handheld or hands-free mobile communication device while driving, except to call 911 in an emergency.","notes":"New Mexico uses a three-stage Graduated Driver Licensing (GDL) system: Instructional Permit (15+), Provisional License (15 years 6 months+, after holding permit 6 months), and Unrestricted Driver License (16 years 6 months+, after holding provisional 12 months crash- and conviction-free). Driver education is required for all applicants under 18 and must include 30 hours classroom, 7 hours behind-the-wheel, and 50 hours supervised practice (10 of which must be nighttime). Of the 50 supervised hours, parents/guardians sign an affidavit (form MVD-10293) attesting to completion.","needsReview":["Exact required night driving hours within the 50 supervised hours (commonly cited as 10)","Whether the cell phone ban for under-18 drivers also applies to passengers or only the driver","Whether the provisional curfew exceptions require written documentation in NM","Current MVD form numbers for the parent affidavit and driver education completion certificate","Whether NM has moved toward electronic submission of the driver-ed completion certificate or remains paper-based"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
