  'rpv_oh_teen_1_0_0', 'rp_oh_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Temporary Instruction Permit Identification Card (TIPIC)","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":24,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":8,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-OH","minPermitAge":15.5,"classroomHoursCompleted":{"gte":24}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Ohio Bureau of Motor Vehicles (Ohio BMV)","minPermitAge":15.5,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"First 12 months (or until age 17): no driving midnight to 6 a.m. unless accompanied by a parent/guardian or for documented work, school, religious, or emergency reasons. Months 12 to 18 (or until age 18): no driving 1 a.m. to 5 a.m. with the same exceptions.","passengerRestriction":"For the first 12 months after licensure (or until age 17), drivers under 17 may not transport more than one non-family passenger unless a parent or guardian is in the vehicle.","cellPhoneRule":"Ohio''s 2023 hands-free law bans drivers of all ages from holding or using a phone or other electronic device while driving. Drivers under 18 are also barred from any use of cell phones or other wireless communication devices while operating a vehicle, even hands-free.","notes":"Ohio''s Graduated Driver Licensing (GDL) program is administered by the Ohio BMV with driver training delivered through Ohio Department of Public Safety (ODPS) approved providers. Teens under 18 must complete a 24-hour classroom (or online) course plus 8 hours of behind-the-wheel instruction with a licensed instructor, then log 50 hours of supervised practice driving (10 of which must be at night) certified by a parent or guardian. Applicants must hold the TIPIC for at least 6 months before testing for a probationary license. Knowledge and vision tests are taken at a BMV Driver Exam Station; the road skills test is administered by a state-contracted third-party examiner.","needsReview":["Exact current fee for the TIPIC and probationary license","Whether the 50-hour log form has been renamed or restructured recently","Current list of ODPS-approved online classroom providers","Any 2025-2026 updates to the hands-free enforcement (primary vs. secondary)","Specific wording of work/school exemption documentation required"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
