INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_oh_how-to-get-an-ohio-tipic_4', 'quiz_oh_how-to-get-an-ohio-tipic', 'While driving on a TIPIC, who must be in the front passenger seat?', '["Any licensed driver 18 or older","Only a certified driving instructor","A licensed parent or guardian, a driving instructor, or (with parental approval) a licensed driver age 21+","Anyone with a valid driver license"]', 2, 'A TIPIC holder must be supervised by a parent/guardian or instructor, or a licensed driver 21+ if the parent/guardian has authorized it.', 4
