  'q_oh_ohio-gdl-restrictions-daily-life_0', 'quiz_oh_ohio-gdl-restrictions-daily-life', 'During the first 12 months of an Ohio probationary license (or until age 17), what nighttime driving rule applies?', '["No driving between 10 p.m. and 5 a.m.","No driving between midnight and 6 a.m. without a parent or guardian","No driving between 1 a.m. and 5 a.m. without any adult","No nighttime restriction once you have any license"]', 1, 'Ohio''s first-tier curfew bans driving from midnight to 6 a.m. without a parent or guardian, with limited work/school/religious/emergency exceptions.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_oh_ohio-gdl-restrictions-daily-life_1', 'quiz_oh_ohio-gdl-restrictions-daily-life', 'How does Ohio''s curfew change after the first 12 months (or after age 17)?', '["All restrictions disappear","It tightens to 10 p.m. to 6 a.m.","It narrows to 1 a.m. to 5 a.m.","It applies only to school nights"]', 2, 'The second-tier Ohio teen curfew applies from 1 a.m. to 5 a.m. until the driver turns 18.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_oh_ohio-gdl-restrictions-daily-life_2', 'quiz_oh_ohio-gdl-restrictions-daily-life', 'In year one of an Ohio probationary license, who can ride with the teen driver?', '["Up to three non-family teens","Only one non-family passenger, unless a parent or guardian is also in the car","Any number of family members or friends","No passengers at all"]', 1, 'Ohio limits new teen drivers to one non-family passenger during the first year unless a parent or guardian is present.', 2
