INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_oh_ohio-specific-rules-and-quirks_2', 'quiz_oh_ohio-specific-rules-and-quirks', 'On a two-lane road, what must you do when a school bus stops with red lights flashing and the stop arm out?', '["Slow to 20 mph and pass with caution","Stop only if you are behind the bus","Stop in both directions at least 10 feet from the bus and remain stopped until the bus moves or lights are off","Pass on the left at any speed"]', 2, 'On a two-lane road, traffic in both directions must stop at least 10 feet from the bus until the lights stop flashing.', 2
