INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_oh_ohio-specific-rules-and-quirks_3', 'quiz_oh_ohio-specific-rules-and-quirks', 'What does an Ohio county Snow Emergency Level 3 mean?', '["Schools are closed but driving is fine","Only commercial trucks must stay off the road","All roadways are closed to non-emergency personnel and driving may be cited as a misdemeanor","Headlights are required even during the day"]', 2, 'Level 3 closes county roads to non-emergency drivers; driving in violation can result in a misdemeanor citation.', 3
