  'rpv_ok_teen_1_0_0', 'rp_ok_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-OK","minPermitAge":15.5,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Oklahoma Department of Public Safety (DPS) - Driver License Services / Service Oklahoma","minPermitAge":15.5,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Intermediate license holders may not drive between 10:00 PM and 5:00 AM unless accompanied by a licensed driver 21 or older, or for work, school, or emergency.","passengerRestriction":"Intermediate license holders may not have more than one passenger in the front seat, and total passengers may not exceed the number of seat belts. Limited to one non-family passenger unless supervised by a licensed driver 21+.","cellPhoneRule":"Drivers under 18 with a learner permit or intermediate license are prohibited from using any handheld electronic communication device while driving. Texting while driving is banned for all drivers statewide.","notes":"Oklahoma''s Graduated Driver License (GDL) program is administered through Service Oklahoma (formerly DPS Driver License Services). Teens who complete an approved driver education course (30 hours classroom + 6 hours behind-the-wheel) may obtain a learner permit at 15 years and 6 months; without driver ed, the minimum permit age is 16. The permit must be held for at least 6 months before advancing to an intermediate license. The intermediate license carries night driving and passenger restrictions until age 16.5 or 6 months of restriction-free driving, whichever is later. A full unrestricted license is available at 16.5 with a clean driving record, or at 17 otherwise. Parent/guardian signature is required for any applicant under 18. Oklahoma uses paper testing at some tag agencies and online scheduling through Service Oklahoma for most road tests.","needsReview":["Exact passenger restriction wording for Oklahoma intermediate license (one non-family passenger rule sourced from training data, may need verification against current Service Oklahoma rules)","Whether the 50-hour supervised practice requirement is statutorily required or only strongly recommended in Oklahoma","Current status of Service Oklahoma transition from DPS Driver License Services - agency naming may have shifted further","Exact age at which intermediate license restrictions lift (16.5 vs 17) under current statute","Whether driver ed waiver/substitution rules still allow 15.5 permit issuance or if minimum has changed"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
