INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ok_oklahoma-gdl-restrictions-daily-life_3', 'quiz_ok_oklahoma-gdl-restrictions-daily-life', 'What is Oklahoma''s rule on cell phone use for drivers under 18 with a permit or intermediate license?', '["Hands-free calls only are allowed","Texting only is banned, calls are fine","All handheld electronic device use is prohibited","Phones may be used at stoplights"]', 2, 'Drivers under 18 with a learner permit or intermediate license may not use any handheld electronic device while driving. Texting is also banned statewide for all drivers.', 3
