INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ok_oklahoma-gdl-restrictions-daily-life_4', 'quiz_ok_oklahoma-gdl-restrictions-daily-life', 'What typically happens if you receive a moving violation during your intermediate license restriction period?', '["Nothing changes if you pay the fine","Restrictions are lifted early as a warning","The restriction period is effectively extended","Your permit converts to a full license automatically"]', 2, 'A moving violation restarts the clean-driving clock, often pushing the end of GDL restrictions out to age 17 or later.', 4
