INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_or_oregon-specific-rules-and-quirks_2', 'quiz_or_oregon-specific-rules-and-quirks', 'Under Oregon law, where is a legal pedestrian crosswalk?', '["Only where painted crosswalks exist","Only at signalized intersections","At every intersection, marked or unmarked","Only at school zones and downtown areas"]', 2, 'Oregon law (ORS 801.220) treats every intersection as a legal crosswalk, marked or not. Drivers must stop for pedestrians accordingly.', 2
