  'rpv_pa_teen_1_0_0', 'rp_pa_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner''s Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":65,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-PA","minPermitAge":16,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Pennsylvania Department of Transportation (PennDOT)","minPermitAge":16,"minLicenseAge":16.5,"minPermitDurationMonths":6,"nighttimeRestriction":"Junior license holders may not drive between 11:00 p.m. and 5:00 a.m. unless traveling to/from work, a volunteer/charitable service, or a school-sponsored activity (with documentation).","passengerRestriction":"For the first 6 months of a junior license: no more than 1 passenger under age 18 who is not an immediate family member. After 6 months (if no violations): up to 3 passengers under age 18. All passengers must wear seat belts; permit holders must be supervised by a licensed driver 21+ in the front seat.","cellPhoneRule":"Pennsylvania bans texting while driving for all drivers. As of 2025, PA also enforces a hands-free law (Paul Miller''s Law) prohibiting handheld mobile device use while driving. Junior drivers should avoid all phone use behind the wheel.","notes":"Pennsylvania requires applicants under 18 to hold the learner''s permit for at least 6 months, complete 65 hours of supervised practice (including 10 hours at night and 5 in inclement weather), and pass a road test. Driver education (classroom + behind-the-wheel) is not state-mandated for licensure but completing an approved 30-hour classroom and 6-hour BTW course qualifies drivers under 18 for an insurance discount and may waive certain skills test requirements at the discretion of insurers. A parent/guardian signature is required for applicants under 18.","needsReview":["Exact insurance discount amount and which carriers honor the 30/6 driver-ed completion","Whether Paul Miller''s hands-free law''s effective date and penalty schedule are current as of 2026","Confirm current PennDOT skills-test waiver policy for completion of state-approved driver education","Verify whether the 5 hours of inclement-weather practice is still officially required vs. recommended"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
