INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_how-to-get-a-pa-learners-permit_2', 'quiz_pa_how-to-get-a-pa-learners-permit', 'Who is qualified to supervise a Pennsylvania learner''s permit holder during practice driving?', '["Any licensed driver age 18 or older","A licensed driver age 21 or older (or a spouse 18+) seated in the front seat","Any adult who has had a license for at least one year","Only a certified driving instructor"]', 1, 'The supervising driver must be 21+ (or a spouse 18+) with a valid license, and must be seated in the front passenger seat.', 2
