  'q_pa_pa-gdl-restrictions-daily-life_0', 'quiz_pa_pa-gdl-restrictions-daily-life', 'What are the nighttime curfew hours for a Pennsylvania junior license holder?', '["10:00 p.m. to 5:00 a.m.","11:00 p.m. to 5:00 a.m.","Midnight to 6:00 a.m.","9:00 p.m. to 6:00 a.m."]', 1, 'Junior license holders may not drive between 11:00 p.m. and 5:00 a.m. except for documented work, volunteer, or school-sponsored activities.', 0
