INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-gdl-restrictions-daily-life_2', 'quiz_pa_pa-gdl-restrictions-daily-life', 'Under Pennsylvania law, when the driver is under 18, who must wear a seat belt?', '["Only the driver and front-seat passenger","Only occupants under age 18","Every occupant in the vehicle, in every seat","Only occupants in the front seat"]', 2, 'When the driver is under 18, every occupant must be belted; this is a primary offense for junior drivers.', 2
