INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-gdl-restrictions-daily-life_3', 'quiz_pa_pa-gdl-restrictions-daily-life', 'Under Paul Miller''s Law (Pennsylvania''s hands-free statute), what is prohibited while driving?', '["Only typing or sending text messages","Only making voice calls without a headset","Holding a mobile device for any purpose while driving","Using GPS apps of any kind"]', 2, 'Paul Miller''s Law prohibits holding a mobile device for any reason while driving; hands-free use is required.', 3
