INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-gdl-restrictions-daily-life_4', 'quiz_pa_pa-gdl-restrictions-daily-life', 'A Pennsylvania junior license automatically becomes an unrestricted license when the holder turns 18, provided they:', '["Pay a $50 conversion fee","Pass an additional skills test","Have no convictions or partial-responsibility crashes in the 12 months prior","Re-take the written knowledge test"]', 2, 'Conversion to an unrestricted license at 18 requires a clean 12-month record (no convictions or partial-fault reportable crashes).', 4
