INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-specific-rules-and-quirks_0', 'quiz_pa_pa-specific-rules-and-quirks', 'At a Pennsylvania intersection with a steady red ARROW for right turns (no sign permitting otherwise), what should you do?', '["Stop, then turn right when traffic is clear","Treat it the same as a round red ball signal","Remain stopped until the arrow turns green — no turn on red arrow","Yield and proceed if there is a turn lane"]', 2, 'A steady red arrow prohibits the turn entirely; you must wait for a green signal. Red ball signals allow right-on-red after a stop where not prohibited.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-specific-rules-and-quirks_1', 'quiz_pa_pa-specific-rules-and-quirks', 'Under Pennsylvania''s Steer Clear / Move Over Law, what must you do when approaching an emergency response area on a multi-lane road?', '["Honk to warn the workers, then drive past at normal speed","Move over one lane if safe, or slow to at least 20 mph below the speed limit if you cannot","Come to a complete stop and wait until directed to proceed","Drive in the shoulder to pass quickly"]', 1, 'Drivers must move over one lane if it is safe, or slow to at least 20 mph below the posted speed limit if moving over is not possible.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-specific-rules-and-quirks_2', 'quiz_pa_pa-specific-rules-and-quirks', 'Pennsylvania law requires your headlights to be on whenever:', '["It is past sunset only","Visibility is less than 100 feet only","Your windshield wipers are in continuous or intermittent use","You are driving on the Pennsylvania Turnpike"]', 2, 'If your wipers are on due to weather, your headlights (not just daytime running lights) must be on as well.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-specific-rules-and-quirks_3', 'quiz_pa_pa-specific-rules-and-quirks', 'A school bus stops with red lights flashing and stop arm extended on a four-lane road with only a painted center turn lane separating directions. What must oncoming traffic do?', '["Continue at reduced speed because the road is divided","Stop, because a painted line is not a physical divider","Slow to 25 mph and pass with caution","Move to the right shoulder and continue"]', 1, 'Painted lines and center turn lanes do not qualify as a physical divider in Pennsylvania; all directions must stop. Violations bring a 60-day suspension, 5 points, and a $250 fine.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_pa_pa-specific-rules-and-quirks_4', 'quiz_pa_pa-specific-rules-and-quirks', 'How does the Pennsylvania Turnpike collect tolls today?', '["Cash booths at each exit only","E-ZPass only — no other payment accepted","Cashless: E-ZPass or Toll By Plate (license plate billing)","Prepaid paper tickets sold at rest stops"]', 2, 'The PA Turnpike is fully cashless: drivers pay via E-ZPass transponder or Toll By Plate, which photographs the license plate and mails an invoice.', 4
);

