  'rpv_ri_teen_1_0_0', 'rp_ri_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Limited Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":33,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":10,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-RI","minPermitAge":16,"classroomHoursCompleted":{"gte":33}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Rhode Island Division of Motor Vehicles (RI DMV)","minPermitAge":16,"minLicenseAge":16.5,"minPermitDurationMonths":6,"nighttimeRestriction":"Provisional license holders under 18 may not drive between 1:00 AM and 5:00 AM unless accompanied by a licensed driver age 21+, or for documented work, school, religious, or emergency reasons.","passengerRestriction":"For the first 12 months of a provisional license, drivers under 18 may not transport more than one passenger under age 21 unless a licensed parent/guardian or driver 21+ is in the vehicle. Immediate family members are exempt.","cellPhoneRule":"Drivers under 18 are prohibited from using any handheld or hands-free electronic communication device while driving. All drivers (any age) are banned from texting, and handheld phone use while driving is prohibited statewide.","notes":"Rhode Island requires teens under 18 to complete a state-approved 33-hour driver education course before obtaining a limited instruction permit. The permit must be held for at least 6 months before a license can be issued. Applicants must also document 50 hours of supervised practice driving, including at least 10 hours at night. Driver education programs typically include a 10-hour behind-the-wheel component. The road test is administered by the RI DMV at the Cranston headquarters or other designated sites.","needsReview":["Whether the 10 BTW hours are part of the 33-hour course requirement or counted separately","Exact permit fee and license fee amounts (these change periodically)","Whether the supervised practice log is submitted on a specific RI DMV form or accepted in any format","Current road test scheduling backlog and whether third-party road testers are authorized in RI","Whether the passenger restriction sunsets at 12 months or extends until age 18"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
