INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ri_rhode-island-specific-rules-and-quirks_1', 'quiz_ri_rhode-island-specific-rules-and-quirks', 'How is the toll on the Claiborne Pell (Newport) Bridge collected?', '["Cash at a tollbooth","Electronically via E-ZPass or plate-billing — no cash booths","On the honor system at a drop box","Only during summer months"]', 1, 'The Pell Bridge is fully electronic — E-ZPass offers the lowest rate, otherwise the system photographs your plate and bills the registered owner.', 1
