INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ri_rhode-island-specific-rules-and-quirks_2', 'quiz_ri_rhode-island-specific-rules-and-quirks', 'What is Rhode Island''s BAC limit for drivers under 21?', '["0.08","0.05","0.02","0.00"]', 2, 'Rhode Island sets an effectively zero-tolerance limit of 0.02 BAC for drivers under 21.', 2
