INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ri_rhode-island-specific-rules-and-quirks_3', 'quiz_ri_rhode-island-specific-rules-and-quirks', 'Under Rhode Island''s Move Over Law, what must you do when approaching a stopped emergency vehicle with flashing lights?', '["Maintain speed and stay in your lane","Honk to warn others","Move over to a non-adjacent lane, or slow significantly if you cannot safely change lanes","Stop completely on the shoulder"]', 2, 'Drivers must move over one lane away from the stopped vehicle, or slow significantly below the posted limit if a safe lane change is not possible.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ri_rhode-island-specific-rules-and-quirks_4', 'quiz_ri_rhode-island-specific-rules-and-quirks', 'What is Rhode Island''s rule connecting windshield wipers and headlights?', '["Headlights must be on only between dusk and dawn","If your wipers are on, your headlights must also be on","Headlights are optional in daytime rain","Only fog lights are required when it rains"]', 1, 'Rhode Island law requires headlights to be on whenever windshield wipers are in use, regardless of the time of day.', 4
);

