  'rpv_sc_teen_1_0_0', 'rp_sc_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Beginner''s Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":40,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-SC","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"South Carolina Department of Motor Vehicles (SCDMV)","minPermitAge":15,"minLicenseAge":16.5,"minPermitDurationMonths":6,"nighttimeRestriction":"Conditional license holders (under 17) may not drive between 6:00 p.m. (Nov-Mar) or 8:00 p.m. (Apr-Oct) and 6:00 a.m. without a licensed adult 21+, except for work, school, or church.","passengerRestriction":"Conditional license holders may not transport more than two passengers under 21 who are not immediate family, unless a licensed parent/guardian is in the front seat.","cellPhoneRule":"South Carolina prohibits texting while driving for all drivers; permit and conditional license holders are strongly discouraged from any handheld phone use. Local ordinances in some cities (e.g., Columbia, Mt. Pleasant) impose stricter handheld bans.","notes":"South Carolina uses a three-stage GDL: Beginner''s Permit (15+), Conditional/Route-Restricted License (15.5+ / 16+), and Special Restricted License lifted at 17. Driver education is required for applicants under 17 to be exempt from the road test waiting period and to obtain a conditional license at 15.5. The 40 hours of supervised practice must include at least 10 hours at night and be logged on the SCDMV-provided log form, signed by a parent or guardian.","needsReview":["Exact minLicenseAge (full unrestricted license vs. conditional license age) — SC has conditional at 16 and full at 17; using 16.5 as a placeholder for the conditional-to-standard transition.","Whether driver-ed BTW requirement is strictly 6 hours statewide or varies by provider/school district.","Current nighttime cutoff times — historically tied to daylight saving (6pm winter / 8pm summer); confirm SCDMV has not updated.","Whether SCDMV now accepts electronic completion certificates from driver-ed providers (would change deliveryMode to electronic_upload).","Exact passenger restriction wording for Beginner''s Permit vs. Conditional License."]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
