INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sc_sc-gdl-restrictions-daily-life_2', 'quiz_sc_sc-gdl-restrictions-daily-life', 'Which of the following is NOT a valid exception to the nighttime curfew?', '["Driving home from your shift at a part-time job","Driving to a church-related activity","Driving home from a friend''s house","Driving with a licensed adult 21+ in the front seat"]', 2, 'Recreational trips, including visits to a friend''s house, are not exceptions. Work, school, church, or supervision by a 21+ adult are the recognized exceptions.', 2
