INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sc_sc-gdl-restrictions-daily-life_4', 'quiz_sc_sc-gdl-restrictions-daily-life', 'Which statement about South Carolina''s distracted-driving law is most accurate?', '["Texting is legal as long as you are stopped at a red light","Texting while driving is banned statewide, and some cities ban any handheld use","Only drivers under 18 are prohibited from texting","There is no statewide law against texting in South Carolina"]', 1, 'South Carolina bans texting for all drivers, and municipalities such as Columbia and Mt. Pleasant additionally prohibit any handheld phone use.', 4
