INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sc_sc-specific-rules-and-quirks_4', 'quiz_sc_sc-specific-rules-and-quirks', 'Which statement about driving in the left lane on a SC multi-lane highway is correct?', '["You may drive in the left lane as long as you are at the speed limit","The left lane is reserved for passing; staying there can be cited as ''left-lane camping''","Left-lane rules apply only to commercial vehicles","There is no SC law about lane usage"]', 1, 'SC Code 56-5-1810 reserves the left lane for passing; lingering there when faster traffic approaches is an enforceable offense.', 4
