INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_sd_teen_1_0_0', 'rp_sd_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-SD","minPermitAge":14,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"South Dakota Department of Public Safety - Driver Licensing Program","minPermitAge":14,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Restricted minor''s permit holders may not drive between 10:00 p.m. and 6:00 a.m. unless accompanied by a licensed parent/guardian or driver 18 or older, or when driving directly to or from work or a school activity.","passengerRestriction":"No specific statewide passenger cap is imposed during the restricted minor''s permit stage beyond the supervising-driver requirement; once licensed at 16 there is no passenger limit, but distracted-driving rules still apply.","cellPhoneRule":"All drivers under 18 are prohibited from using a wireless communication device (handheld or hands-free) while driving, except to report an emergency. Texting while driving is illegal for ALL drivers statewide.","notes":"South Dakota has one of the youngest minimum permit ages in the nation (14). A 14-year-old may obtain an instruction permit after passing the written and vision tests. After holding the permit at least 6 months with no violations and completing 50 hours of supervised driving (including 10 at night), a teen may obtain a restricted minor''s permit at 14 years and 6 months. A full unrestricted operator''s license is available at age 16 (or earlier if the teen completes an approved driver education course AND has held the restricted minor''s permit for at least 180 days without a violation).","needsReview":["Exact number of supervised practice hours required by statute (commonly cited as 50 with 10 night hours, but South Dakota''s statutory text should be confirmed)","Whether classroom hours of 30 are state-mandated or industry-standard (SD does not require driver ed for licensing, but providers typically follow 30/6)","Precise wording of the 10 p.m. to 6 a.m. curfew exceptions","Current passenger restrictions under the restricted minor''s permit (statute revisions)","Whether the hands-free/texting law has changed recently"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
