INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sd_how-to-get-a-permit-in-south-dakota_2', 'quiz_sd_how-to-get-a-permit-in-south-dakota', 'How long must an instruction permit be held (violation-free) before a teen can move to the restricted minor''s permit?', '["30 days","90 days","6 months","12 months"]', 2, 'The permit must be held for at least 6 months with no moving violations before advancing to the restricted minor''s permit.', 2
