INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sd_how-to-get-a-permit-in-south-dakota_3', 'quiz_sd_how-to-get-a-permit-in-south-dakota', 'How many hours of supervised driving practice are required before the restricted minor''s permit, and how many must be at night?', '["30 total / 5 at night","40 total / 8 at night","50 total / 10 at night","60 total / 12 at night"]', 2, 'South Dakota expects 50 supervised hours, including 10 at night, logged before advancing to the restricted minor''s permit.', 3
