INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sd_how-to-get-a-permit-in-south-dakota_4', 'quiz_sd_how-to-get-a-permit-in-south-dakota', 'Which document combination is acceptable proof of South Dakota residency at the Exam Station?', '["One photocopy of a utility bill","Two documents showing your physical SD address (e.g., utility bill + bank statement)","A friend''s verbal confirmation","Your school yearbook"]', 1, 'South Dakota requires TWO documents showing your physical residential address - originals, not photocopies, especially for REAL ID.', 4
