INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sd_south-dakota-specific-rules-and-quirks_2', 'quiz_sd_south-dakota-specific-rules-and-quirks', 'When a school bus on a two-lane road has its red lights flashing and stop arm extended, who must stop?', '["Only vehicles behind the bus","Only vehicles in the opposite lane","Drivers on BOTH sides of the road","No one if traffic is light"]', 2, 'On a two-lane road, drivers in both directions must stop. Only a physical median/divided highway exempts oncoming traffic.', 2
