  'rpv_tn_teen_1_0_0', 'rp_tn_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-TN","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Tennessee Department of Safety and Homeland Security, Driver Services Division","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Intermediate Restricted License holders may not drive between 11:00 PM and 6:00 AM unless accompanied by a parent or licensed adult 21+, or for documented work, school, or church activity.","passengerRestriction":"Intermediate Restricted License holders may carry only one passenger; Intermediate Unrestricted License holders may carry no more than three passengers under 18 who are not immediate family.","cellPhoneRule":"Drivers under 18 may not use a cell phone or other wireless device while driving (hands-free or handheld). All Tennessee drivers are prohibited from holding a phone or texting while driving under the statewide hands-free law.","notes":"Tennessee uses a three-stage Graduated Driver License (GDL) program: Learner Permit (age 15), Intermediate Restricted License (age 16), and Intermediate Unrestricted License (age 17). The 50 hours of supervised practice (10 at night) is required before the road skills test. Driver education is not state-mandated for licensing, but many schools and insurers offer/require it. Tennessee does not issue a single ''completion certificate'' that automatically credentials a permit; eligibility is verified by DOS Driver Services at the testing center based on age, parental consent (under 18), and documentation. School attendance compliance (SADAP) is enforced: students who drop out or have excessive absences can have their permit/license revoked.","needsReview":["Exact wording of TN cell phone statute for under-18 drivers vs statewide hands-free law","Whether TN counts certified driver-ed BTW hours toward the 50-hour supervised practice requirement","Current fee for Learner Permit and Intermediate License","Whether the Intermediate Unrestricted License is automatic at age 17 or requires application","SADAP (School Attendance and Dropout Prevention) reporting cadence between schools and DOS"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
