INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_tn_how-to-get-a-tn-learner-permit_1', 'quiz_tn_how-to-get-a-tn-learner-permit', 'Which Tennessee agency issues the Learner Permit?', '["Tennessee Department of Transportation","Tennessee Department of Revenue","Tennessee Department of Safety and Homeland Security, Driver Services Division","Tennessee Secretary of State"]', 2, 'The Driver Services Division of the Department of Safety and Homeland Security issues all Tennessee driver credentials.', 1
