INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_tn_how-to-get-a-tn-learner-permit_2', 'quiz_tn_how-to-get-a-tn-learner-permit', 'How long must a teen hold a Tennessee Learner Permit before applying for an Intermediate Restricted License?', '["30 days","90 days","180 days (6 months)","12 months"]', 2, 'Tennessee requires a 180-day (6-month) permit holding period with no traffic or seat-belt convictions.', 2
