INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_tx_tx-gdl-daily-life_4', 'quiz_tx_tx-gdl-daily-life', 'When do the Texas provisional license passenger and nighttime restrictions automatically end?', '["After 6 months","On the earlier of 12 months from issuance or the driver''s 18th birthday","Only on the driver''s 18th birthday","After completing an additional driving course"]', 1, 'The restrictions lift on the earlier of 12 months after the provisional license was issued or the driver''s 18th birthday.', 4
