INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_tx_tx-ittd-and-quirks_1', 'quiz_tx_tx-ittd-and-quirks', 'Under Texas''s Move Over law, what must a driver do when approaching a stopped emergency or TxDOT vehicle with lights flashing on a 65 mph highway?', '["Stop completely until the vehicle moves","Move over one lane OR slow down to 45 mph","Honk twice to acknowledge the vehicle","Move over one lane only — slowing down is not an option"]', 1, 'On a 65 mph road, drivers must move over one lane away from the stopped vehicle or slow down to 20 mph below the limit (45 mph).', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_tx_tx-ittd-and-quirks_2', 'quiz_tx_tx-ittd-and-quirks', 'What is Texas''s minimum required liability insurance coverage (30/60/25)?', '["$30,000 / $60,000 / $25,000","$30,000 / $60,000 / $25,000 per year","$3,000 / $6,000 / $2,500 per claim","$60,000 per person, $30,000 per accident, $25,000 property"]', 0, 'Texas requires 30/60/25 coverage: $30,000 bodily injury per person, $60,000 per accident, and $25,000 property damage.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_tx_tx-ittd-and-quirks_3', 'quiz_tx_tx-ittd-and-quirks', 'On a four-lane undivided road in Texas, a school bus stops with its red lights flashing and stop arm out. Who must stop?', '["Only vehicles traveling in the same direction as the bus","Only vehicles in the lane directly next to the bus","Drivers from both directions","Only vehicles within 50 feet of the bus"]', 2, 'On an undivided road, Texas law requires drivers from both directions to stop. Only a physical barrier or median between lanes exempts oncoming traffic.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_tx_tx-ittd-and-quirks_4', 'quiz_tx_tx-ittd-and-quirks', 'Under Texas''s zero-tolerance law for minors, what blood alcohol level is permitted for a driver under 21?', '["0.08% — same as adults","0.04%","0.02%","Any detectable amount is a violation"]', 3, 'Texas has zero tolerance: any detectable amount of alcohol in a driver under 21 is a violation, regardless of impairment level.', 4
);

