  'rpv_ut_teen_1_0_0', 'rp_ut_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":40,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-UT","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Utah Driver License Division (DLD)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"For the first six months after licensing, drivers under 18 may not drive between midnight and 5:00 a.m. unless accompanied by a licensed parent/guardian or for an exempt purpose (employment, school activity, medical emergency, religious activity).","passengerRestriction":"For the first six months after licensing, drivers under 18 may not transport any passenger under 21 who is not an immediate family member, unless accompanied by a licensed driver 21+ in the front seat.","cellPhoneRule":"Handheld cell phone use (manipulating a phone, texting, dialing, browsing) while driving is prohibited for all drivers. Drivers under 18 may not use a wireless communication device at all while driving except to report an emergency.","notes":"Utah requires teens (under 18) to complete a state-approved driver education course consisting of 30 hours of classroom instruction, 6 hours of behind-the-wheel training with a certified instructor, and 6 hours of in-car observation. In addition, the teen must log 40 hours of supervised practice driving (10 of which must be at night) with a licensed driver age 21+. The learner permit must be held for at least 6 months before a license can be issued, and the teen must be 16. Utah uses a paper Driving Privilege Card / certificate of completion that the student presents at the DLD office; there is no statewide electronic completion API for private driver ed schools, so completion is recorded on form DLD-41 (Driver Education Certificate) signed by the school.","needsReview":["Confirm exact required observation hours (commonly 6) vs behind-the-wheel hours","Confirm current DLD completion form number (DLD-41) is still in use in 2026","Verify whether Utah has moved any portion of driver-ed reporting to an electronic submission portal","Verify exact wording of the nighttime curfew exemptions in current Utah Code 53-3-211"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
