INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ut_how-to-get-a-utah-learner-permit_3', 'quiz_ut_how-to-get-a-utah-learner-permit', 'Which of the following is NOT required at the DLD office when applying for a learner permit?', '["Parent or guardian signature","Vision screening","Behind-the-wheel road test","Proof of Utah residency"]', 2, 'The road (skills) test is required for the license, not for the learner permit. Only the written knowledge and vision tests are taken at the permit stage.', 3
