INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ut_utah-specific-rules-and-quirks_1', 'quiz_ut_utah-specific-rules-and-quirks', 'When must you turn on your headlights in Utah?', '["Only at night","Only in heavy snow","Anytime your windshield wipers are in continuous use","Only when visibility is under 500 feet"]', 2, 'Utah''s ''wipers on, lights on'' rule requires headlights any time wipers are in continuous use due to weather.', 1
