INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ut_utah-specific-rules-and-quirks_2', 'quiz_ut_utah-specific-rules-and-quirks', 'On a two-lane road in Utah, who must stop when a school bus displays flashing red lights and extends its stop arm?', '["Only traffic behind the bus","Only traffic in the oncoming lane","Traffic in both directions","Only school zone traffic"]', 2, 'On an undivided road, traffic in both directions must stop. Only a physical median exempts oncoming traffic.', 2
