INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ut_utah-specific-rules-and-quirks_3', 'quiz_ut_utah-specific-rules-and-quirks', 'Utah''s Move-Over law requires you to change lanes or slow down for which of the following?', '["Only police vehicles with lights on","Only fire and EMS vehicles","Any stopped vehicle displaying flashing lights, including tow trucks and motorists with hazards","Only UDOT maintenance vehicles"]', 2, 'Utah''s Move-Over law applies to any stopped vehicle with flashing lights — emergency, tow, UDOT, and even ordinary motorists using hazards on the shoulder.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_ut_utah-specific-rules-and-quirks_4', 'quiz_ut_utah-specific-rules-and-quirks', 'During winter months in Little Cottonwood and Big Cottonwood Canyons, UDOT may require:', '["Studded tires only","Snow tires, all-season M+S tires, or chains","All-wheel drive only","Chains on all four tires"]', 1, 'The canyon traction law (Nov 1–Apr 30) requires snow tires, all-season M+S rated tires, or chains when posted.', 4
);

