INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_va_teen_1_0_0', 'rp_va_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner''s Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":36,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":14,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":45,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-VA","minPermitAge":15.5,"classroomHoursCompleted":{"gte":36}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Virginia Department of Motor Vehicles (DMV)","minPermitAge":15.5,"minLicenseAge":16.25,"minPermitDurationMonths":9,"nighttimeRestriction":"For the first year after licensure (or until age 18, whichever comes first), drivers under 18 may not drive between midnight and 4:00 a.m. except for limited reasons (driving to/from work, a school-sanctioned activity, a religious event, a medical emergency, or when accompanied by a licensed parent or guardian).","passengerRestriction":"During the first year of licensure, drivers under 18 may carry only one passenger under age 21 who is not a family member. After the first year and until age 18, no more than three passengers under age 21 who are not family members. Does not apply when a licensed parent/guardian or other licensed adult 21+ is in the front seat.","cellPhoneRule":"Drivers under 18 are prohibited from using any handheld personal communications device (including hands-free) while operating a motor vehicle. All Virginia drivers are banned from holding a handheld device while driving, and texting while driving is a primary offense for all drivers.","notes":"Virginia requires 45 hours of supervised practice driving (15 of which must be after sunset) logged by a parent or guardian on DMV Form DEC 1. Teens under 18 must hold the learner''s permit for at least 9 months before being eligible for a driver''s license. After completing driver education, teens under 18 typically receive their license via a juvenile court ceremony presided over by a judge. Virginia mandates a 36/90/14 driver education curriculum: 36 classroom periods (or equivalent), 90 minutes of parent/teen driving component, and 14 in-car periods (7 behind-the-wheel + 7 observation).","needsReview":["Exact minimum license age (commonly cited as 16 years and 3 months, expressed here as 16.25)","Whether ''manual'' is the correct delivery mode versus ''electronic_upload'' given recent DMV portal modernization","Current passenger restriction thresholds (one passenger under 21 first year, three thereafter) — confirm against latest Code of Virginia 46.2-334.01","Confirmation that the cell phone ban for under-18 drivers covers all hands-free use, not only handheld","Whether the 90-minute parent/teen component is still required as of current curriculum standards","Exact required nighttime practice hours within the 45-hour supervised practice (commonly 15)"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
