INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_va_virginia-specific-rules-and-quirks_0', 'quiz_va_virginia-specific-rules-and-quirks', 'In Virginia, where do most teens receive their first driver''s license?', '["At a DMV customer service center","By mail after submitting Form DEC 1","At a juvenile and domestic relations district court ceremony","At their high school''s driver education department"]', 2, 'Virginia traditionally presents teen driver''s licenses at a juvenile court ceremony where a judge addresses the new drivers and emphasizes the responsibilities of licensure.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_va_virginia-specific-rules-and-quirks_1', 'quiz_va_virginia-specific-rules-and-quirks', 'At what speed does driving on a Virginia highway automatically meet the threshold for reckless driving, regardless of the posted limit?', '["Over 70 mph","Over 75 mph","Over 80 mph","Over 85 mph"]', 3, 'In Virginia, driving over 85 mph on any road is reckless driving — a Class 1 misdemeanor punishable by up to 12 months in jail, a $2,500 fine, and license suspension.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_va_virginia-specific-rules-and-quirks_2', 'quiz_va_virginia-specific-rules-and-quirks', 'Under Virginia''s Move Over law, what must a driver do when approaching a stationary vehicle on the shoulder with flashing lights?', '["Maintain speed and stay in the same lane","Change lanes if safe; otherwise slow down and proceed cautiously","Stop completely until the emergency vehicle moves","Honk to acknowledge the stopped vehicle"]', 1, 'Virginia drivers must move over a lane when safe, or slow down and proceed with caution if a lane change isn''t safe. The rule applies to any vehicle with flashing emergency, amber, blue, red, or white lights.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_va_virginia-specific-rules-and-quirks_3', 'quiz_va_virginia-specific-rules-and-quirks', 'Which device is illegal to possess in a passenger vehicle in Virginia, even if unplugged?', '["Dash camera","Radar detector","GPS navigation unit","CB radio"]', 1, 'Virginia is one of the few U.S. jurisdictions that bans radar detectors in passenger vehicles. Mere possession can result in a fine and confiscation.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_va_virginia-specific-rules-and-quirks_4', 'quiz_va_virginia-specific-rules-and-quirks', 'Under Virginia law, when must your headlights be turned on?', '["Only between sunset and sunrise","Whenever your windshield wipers are in use due to weather, or visibility is under 500 feet","Only on interstate highways","Only when daytime running lights are unavailable"]', 1, 'Virginia''s ''wipers on, lights on'' rule requires headlights any time wipers are in use because of weather, or when visibility drops below 500 feet. Daytime running lights alone don''t satisfy the law because they often don''t engage the taillights.', 4
);

