INSERT OR REPLACE INTO rule_pack_version (id, rulePackId, version, definition, publishedAt, notes, createdAt) VALUES (
  'rpv_vt_teen_1_0_0', 'rp_vt_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Learner Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":40,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-VT","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Vermont Department of Motor Vehicles (DMV)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":12,"nighttimeRestriction":"Junior operators may not drive between sunset and sunrise without a licensed parent, guardian, or person at least 25 years old in the front seat.","passengerRestriction":"For the first 3 months of a Junior License, no passengers except immediate family; for the next 3 months, no passengers under 25 unless a licensed parent/guardian or person 25+ is in the front seat. Restriction lifts after 6 months or at age 18.","cellPhoneRule":"All handheld cell phone and electronic device use is prohibited for drivers under 18 (junior operators), including hands-free. Vermont also bans handheld device use for all drivers statewide.","notes":"Vermont uses a Graduated Driver License (GDL) system administered by the Vermont DMV. Teens must be at least 15 to get a Learner Permit, hold it for a minimum of 12 months with no suspensions and no driving convictions in the most recent 6 months, complete a state-approved driver education course (30 hours classroom + 6 hours behind-the-wheel), log at least 40 hours of supervised practice (10 of which must be at night), and pass a road test to receive a Junior Driver License. Vermont law allows the road test to be waived in some cases when completed through certain approved driver education programs, but this is administered locally. The full operator license is issued at age 18 or after meeting all Junior License restrictions for the required period.","needsReview":["Exact number of required nighttime supervised practice hours (commonly cited as 10 of the 40)","Whether the road test waiver applies broadly through driver education or only in specific programs","Precise wording of the passenger restriction phase-in (3+3 month structure)","Whether handheld bans for under-18 drivers extend to all electronic devices including GPS","Current fee schedule for the Learner Permit and Junior License"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
