INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_how-to-get-a-vermont-learner-permit_2', 'quiz_vt_how-to-get-a-vermont-learner-permit', 'When driving with a Learner Permit in Vermont, who must be seated next to you?', '["Any licensed driver age 18 or older","A licensed driver at least 21 years old","A licensed parent, guardian, driver ed instructor, or licensed driver at least 25 years old","Only a certified driving instructor"]', 2, 'The supervising adult must be a licensed parent, guardian, driver education instructor, or a licensed driver at least 25 years old, seated in the front passenger seat.', 2
);
