INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-gdl-restrictions-daily-life_2', 'quiz_vt_vermont-gdl-restrictions-daily-life', 'What is Vermont''s cell phone rule for drivers under 18?', '["Handheld use prohibited; hands-free allowed","All cell phone use is prohibited, including hands-free","Only texting is prohibited","Phone use is allowed at stop signs and red lights"]', 1, 'Drivers under 18 in Vermont may not use any electronic device, including hands-free systems.', 2
