INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-gdl-restrictions-daily-life_3', 'quiz_vt_vermont-gdl-restrictions-daily-life', 'What is Vermont''s blood alcohol limit for drivers under 21 under the zero-tolerance law?', '["0.00%","0.02%","0.05%","0.08%"]', 1, 'Vermont''s zero-tolerance law sets the under-21 BAC limit at 0.02%, well below the adult 0.08% threshold.', 3
