INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-gdl-restrictions-daily-life_4', 'quiz_vt_vermont-gdl-restrictions-daily-life', 'After how long can a Junior Driver License holder typically drive friends without a qualified adult in the car?', '["30 days after the JDL is issued","3 months after the JDL is issued","6 months after the JDL is issued, or at age 18","Never, until they get a full operator license at age 21"]', 2, 'Vermont''s passenger restriction lifts after 6 months of holding the JDL, or when the driver turns 18 — whichever comes first.', 4
