INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-specific-road-rules-and-quirks_0', 'quiz_vt_vermont-specific-road-rules-and-quirks', 'On a narrow Vermont mountain road where two vehicles cannot pass, which vehicle has the right of way?', '["The vehicle traveling downhill","The vehicle traveling uphill","The larger vehicle","Whichever vehicle is closer to a pullout"]', 1, 'The uphill vehicle has the right of way because it is harder to restart on a steep grade; the downhill driver should find a pullout and yield.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-specific-road-rules-and-quirks_1', 'quiz_vt_vermont-specific-road-rules-and-quirks', 'When are studded tires legal in Vermont?', '["Year-round","November 1 through April 30","December 1 through March 31","Only during declared winter emergencies"]', 1, 'Vermont allows studded tires from November 1 through April 30.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-specific-road-rules-and-quirks_2', 'quiz_vt_vermont-specific-road-rules-and-quirks', 'If a moose is suddenly standing in the road in front of you, what is the recommended action?', '["Swerve sharply to avoid the animal","Brake hard and stay in your lane","Accelerate and pass beside it","Honk and continue at the same speed"]', 1, 'Swerving often causes a worse crash. Brake hard, stay in your lane, and try to scrub off as much speed as possible before impact.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-specific-road-rules-and-quirks_3', 'quiz_vt_vermont-specific-road-rules-and-quirks', 'Vermont law requires you to turn on your headlights whenever you are using which equipment?', '["Your defroster","Your turn signals","Your windshield wipers","Your hazard lights"]', 2, 'If your wipers are on due to weather, your headlights must be on as well.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_vt_vermont-specific-road-rules-and-quirks_4', 'quiz_vt_vermont-specific-road-rules-and-quirks', 'On a two-lane Vermont road, when must you stop for a school bus with flashing red lights?', '["Only traffic behind the bus must stop","Only traffic in front of the bus must stop","Traffic in both directions must stop","Stopping is optional if the bus is partly off the road"]', 2, 'On an undivided two-lane road, traffic in both directions must stop for a school bus displaying flashing red lights.', 4
);

