  'rpv_wa_teen_1_0_0', 'rp_wa_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-WA","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Washington State Department of Licensing (DOL)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"For the first 6 months after licensing, no driving between 1 a.m. and 5 a.m. unless accompanied by a licensed driver age 25 or older. From months 7-12, the restriction continues unless an exception applies (work, school, agricultural activity, or with a supervising adult).","passengerRestriction":"For the first 6 months after licensing, no passengers under age 20 (except immediate family). For the next 6 months, no more than 3 passengers under age 20 (except immediate family).","cellPhoneRule":"Drivers under 18 with an intermediate license may not use any wireless device (including hands-free) while driving, except to report an emergency. All Washington drivers are prohibited from holding a personal electronic device while driving under the E-DUI law (RCW 46.61.672).","notes":"Washington requires teens under 18 to complete a Driver Training Education (DTE) course from a DOL-licensed driver training school. The required 50 hours of supervised practice must include 10 hours at night. The intermediate license is in effect until the driver turns 18 or has had the license for 12 months without traffic violations, whichever comes first. Washington uses a ''Traffic Safety Education'' completion certificate that schools submit electronically to DOL via the DRIVES system, but for purposes of this overlay we mark the credential as manual since not every school is integrated.","needsReview":["Whether permitCredentialDeliveryMode should be ''electronic_upload'' or ''api'' for DOL DRIVES integration in 2026","Exact current passenger restriction wording and any 2025/2026 legislative updates","Whether the 10 night-hour subset of the 50 practice hours has changed","Current fee schedule for instruction permit and intermediate license (not captured here)"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
