INSERT OR REPLACE INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_wi_overlay', 'course_wi_overlay', 'wi-teen-overlay', 'Wisconsin Teen Driver Overlay', 'Wisconsin-specific supplemental lessons covering how to obtain an instruction permit through the WisDOT DMV, how the Graduated Driver Licensing (GDL) restrictions apply day-to-day, and the state-specific rules and quirks every new Wisconsin driver should know.', 0
