INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wi_how-to-get-a-wisconsin-instruction-permit_4', 'quiz_wi_how-to-get-a-wisconsin-instruction-permit', 'What is the minimum amount of time you must hold a Wisconsin instruction permit before applying for a probationary license?', '["3 months","6 months","9 months","12 months"]', 1, 'Wisconsin requires the instruction permit to be held for at least 6 months, with no convictions in the 6 months immediately before applying for the probationary license.', 4
