INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wi_wisconsin-specific-rules-and-quirks_1', 'quiz_wi_wisconsin-specific-rules-and-quirks', 'What is the recommended action if a deer suddenly enters your lane and a collision appears unavoidable?', '["Swerve sharply to the left into the oncoming lane","Swerve right onto the shoulder regardless of conditions","Brake firmly, stay in your lane, and hit it straight on","Accelerate to clear the deer''s path"]', 2, 'Swerving causes most fatal deer-collision injuries. Brake firmly, stay in your lane, and accept a straight-on impact if unavoidable.', 1
