INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wi_wisconsin-specific-rules-and-quirks_2', 'quiz_wi_wisconsin-specific-rules-and-quirks', 'Wisconsin''s basic speed law means:', '["You may always drive up to the posted speed limit","You must drive at least 10 mph under the limit in winter","You can be cited for driving too fast for conditions even when below the posted limit","Speed limits do not apply on rural roads"]', 2, 'Wisconsin''s basic speed law requires drivers to operate at a reasonable and prudent speed for current conditions, regardless of the posted limit.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wi_wisconsin-specific-rules-and-quirks_3', 'quiz_wi_wisconsin-specific-rules-and-quirks', 'When entering a Wisconsin roundabout, you must:', '["Yield to traffic already in the roundabout, including the inside lane","Stop completely before entering, even if no traffic is present","Take the outside lane for any left turn","Signal as you enter"]', 0, 'Drivers entering a roundabout must yield to all traffic already circulating, including vehicles in the inside lane.', 3
