INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wi_wisconsin-specific-rules-and-quirks_4', 'quiz_wi_wisconsin-specific-rules-and-quirks', 'When does Wisconsin law require your headlights to be on?', '["Only after full sunset until full sunrise","From 30 minutes after sunset until 30 minutes before sunrise, and whenever weather reduces visibility","Only when driving above 45 mph","Only when daytime running lights are inoperative"]', 1, 'Wisconsin requires headlights (not just DRLs) from 30 minutes after sunset to 30 minutes before sunrise, and whenever weather reduces visibility below 500 feet.', 4
);

