  'rpv_wv_teen_1_0_0', 'rp_wv_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Level 1 Instruction Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-WV","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"West Virginia Division of Motor Vehicles (WV DMV)","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":6,"nighttimeRestriction":"Level 2 (Intermediate) drivers may not drive between 10:00 p.m. and 5:00 a.m. unless accompanied by a licensed driver age 21+, or for documented work, school, religious, or emergency purposes.","passengerRestriction":"During the first 6 months at Level 2, no non-family passengers under age 20 are allowed. During the second 6 months, no more than one non-family passenger under age 20. After 12 months at Level 2, no more than three non-family passengers under age 20 until age 18.","cellPhoneRule":"Drivers under 18 are prohibited from using any wireless communication device while driving, including hands-free. All West Virginia drivers are banned from texting and from using a handheld phone while driving.","notes":"West Virginia uses a three-level GDL system: Level 1 (Instruction Permit) at 15, Level 2 (Intermediate License) at 16 after holding the permit for at least 180 days with 50 hours of supervised driving (including 10 at night), and Level 3 (Full License) at 17 (or 18 if the driver has any violations during Level 2). Applicants under 18 must show proof of school enrollment or a high school diploma/GED, and successful completion of a state-approved driver education course can reduce the required permit holding period. Driver education is offered through many WV public high schools but is not strictly mandatory; the supervised practice requirement applies to all teen applicants.","needsReview":["Exact required classroom hours for state-approved driver education programs in WV (commonly cited as 30 but varies by school)","Exact BTW hours required by WV driver education programs (6 is the commonly cited minimum but not universally codified)","Whether completion of driver education reduces the 180-day permit hold (some sources suggest yes, others no)","Exact phrasing and statute citation for the nighttime and passenger restrictions","Current cell phone statute citation and whether enforcement is primary or secondary for adults"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
