INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wv_wv-specific-rules-and-quirks_1', 'quiz_wv_wv-specific-rules-and-quirks', 'What does West Virginia''s Move Over Law require when you approach a stopped emergency or tow vehicle with flashing lights?', '["Honk to alert the workers","Move over one lane if safe, or slow down significantly","Stop completely until waved through","Turn on your hazard lights and continue at the speed limit"]', 1, 'Drivers must move over one lane when safe, or reduce speed below the posted limit if they cannot change lanes.', 1
