INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wv_wv-specific-rules-and-quirks_2', 'quiz_wv_wv-specific-rules-and-quirks', 'On a two-lane West Virginia road with a school bus displaying flashing red lights and an extended stop arm, who must stop?', '["Only traffic following the bus","Only traffic in the oncoming lane","Traffic in both directions","No one, as long as you slow to 15 mph"]', 2, 'On a two-lane road, traffic in BOTH directions must stop. Only on a physically divided highway may oncoming traffic proceed.', 2
