INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wv_wv-specific-rules-and-quirks_3', 'quiz_wv_wv-specific-rules-and-quirks', 'What is the BAC limit that constitutes DUI for a driver under 21 in West Virginia?', '["0.08%","0.05%","0.04%","0.02%"]', 3, 'WV''s zero-tolerance law sets the under-21 DUI threshold at 0.02% BAC.', 3
