INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wv_wv-specific-rules-and-quirks_4', 'quiz_wv_wv-specific-rules-and-quirks', 'Under West Virginia law, when must your headlights (not just daytime running lights) be on?', '["Only between sunset and sunrise","Only in heavy fog","Whenever weather conditions require continuous use of the windshield wipers, and from sunset to sunrise","Only on interstate highways"]', 2, 'WV requires full headlights from sunset to sunrise AND whenever wipers are in continuous use due to weather.', 4
);

