  'rpv_wy_teen_1_0_0', 'rp_wy_teen', '1.0.0', '{"credentials":[{"key":"permit_eligibility","label":"Wyoming Learner Permit","deliveryMode":"manual"}],"requirements":[{"key":"classroom_hours","label":"Classroom hours","target":30,"unit":"hour"},{"key":"btw_hours","label":"Behind-the-wheel hours","target":6,"unit":"hour"},{"key":"supervised_practice_hours","label":"Supervised practice (parent log)","target":50,"unit":"hour"}],"rules":[{"key":"unlock_permit_eligibility","trigger":"enrollment.state_changed","conditions":{"jurisdiction":"US-WY","minPermitAge":15,"classroomHoursCompleted":{"gte":30}},"actions":[{"type":"unlock_credential","credential":"permit_eligibility"},{"type":"set_journey_state","value":"permit_eligible"}]}],"facts":{"agencyName":"Wyoming Department of Transportation (WYDOT) Driver Services","minPermitAge":15,"minLicenseAge":16,"minPermitDurationMonths":10,"nighttimeRestriction":"Intermediate license holders may not drive between 11:00 PM and 5:00 AM unless accompanied by a licensed driver 18 or older, or for work, school, or religious activities.","passengerRestriction":"Intermediate license holders may not transport more than one passenger under age 18 who is not an immediate family member.","cellPhoneRule":"Wyoming prohibits texting while driving for all drivers. Use of handheld cell phones is restricted in school zones and certain municipalities (e.g., Cheyenne, Laramie) have stricter local ordinances. All drivers under 18 are strongly discouraged from any cell phone use while driving.","notes":"Wyoming has a three-stage Graduated Driver License (GDL) program: Learner Permit (15+), Intermediate Permit (16+), and Unrestricted License (17+). Driver education is not strictly required statewide but completion can waive certain waiting periods or testing requirements at WYDOT discretion. Rural areas of Wyoming have a hardship/restricted permit available at age 14 for farm and family transportation needs. Wyoming is largely rural with long highway distances, severe winter weather (black ice, blowing snow, I-80 closures), and high wildlife collision rates (deer, antelope, elk). The state has some of the highest posted speed limits in the U.S. (up to 80 mph on rural interstates).","needsReview":["Exact required classroom hours for state-approved driver education (30 is typical but WY does not mandate driver ed statewide)","Exact required BTW hours for approved courses (6 is typical industry standard)","Whether minPermitDurationMonths is 10 or a different value for applicants who complete approved driver education","Current nighttime restriction window (some sources cite 11 PM-5 AM, others 11 PM-6 AM)","Whether handheld phone ban applies statewide to all drivers or only texting and certain zones","Eligibility age and exact restrictions for the rural/hardship permit (sometimes cited as 14, sometimes 15)","Whether WYDOT accepts third-party completion certificates electronically or only paper"]}}', unixepoch('now')*1000, 'Generated; school must review and tweak.', unixepoch('now')*1000
);
