INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_how-to-get-a-wyoming-learner-permit_1', 'quiz_wy_how-to-get-a-wyoming-learner-permit', 'How many hours of supervised driving practice must a Wyoming learner permit holder complete before upgrading to an intermediate license?', '["20 hours","30 hours","50 hours","100 hours"]', 2, 'Wyoming requires 50 hours of supervised practice, including at least 10 hours after dark, before a teen can apply for the intermediate license.', 1
