INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-gdl-restrictions-in-daily-life_0', 'quiz_wy_wyoming-gdl-restrictions-in-daily-life', 'During which hours does the Wyoming intermediate license nighttime restriction apply?', '["9:00 PM to 5:00 AM","10:00 PM to 6:00 AM","11:00 PM to 5:00 AM","Midnight to 6:00 AM"]', 2, 'The Wyoming nighttime restriction for intermediate license holders runs from 11:00 PM to 5:00 AM.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-gdl-restrictions-in-daily-life_1', 'quiz_wy_wyoming-gdl-restrictions-in-daily-life', 'Which of the following is NOT an exemption to the Wyoming nighttime driving restriction?', '["Driving directly home from a work shift","Driving to a friend''s house to hang out","Driving to a school-sanctioned event","Driving with a licensed adult age 18 or older in the front seat"]', 1, 'Social or recreational driving is not exempt. The exemptions are for work, school activities, religious activities, emergencies, or when supervised by an adult 18 or older.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-gdl-restrictions-in-daily-life_2', 'quiz_wy_wyoming-gdl-restrictions-in-daily-life', 'How many non-family passengers under age 18 may a Wyoming intermediate license holder carry when no adult supervisor is in the vehicle?', '["Zero","One","Two","Unlimited"]', 1, 'Only one passenger under 18 who is not an immediate family member is allowed unless a licensed adult 18 or older is also in the vehicle.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-gdl-restrictions-in-daily-life_3', 'quiz_wy_wyoming-gdl-restrictions-in-daily-life', 'When does a Wyoming teen automatically graduate from intermediate license restrictions to an unrestricted license?', '["At age 16 ½","After holding the intermediate license for 6 months","On their 17th birthday","On their 18th birthday"]', 2, 'Wyoming intermediate license restrictions lift automatically on the holder''s 17th birthday — no retest or reapplication required.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-gdl-restrictions-in-daily-life_4', 'quiz_wy_wyoming-gdl-restrictions-in-daily-life', 'Your shift ends at 11:15 PM. You drive a friend home, then stop for fast food, then drive home. Is this allowed under your Wyoming intermediate license?', '["Yes — the work exemption covers the whole trip","Yes — as long as your friend is under 18 and there is only one of them","No — the work exemption only covers driving directly home, and the passenger may also violate the passenger rule","Yes — as long as you''re home by midnight"]', 2, 'The work exemption applies only to direct travel between work and home. Detours forfeit the exemption, and the non-family teen passenger is also a separate restriction.', 4
);
INSERT OR REPLACE INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_wy_wyoming-specific-rules-and-quirks', 'module_wy_overlay', 'wyoming-specific-rules-and-quirks', 'Wyoming-Specific Rules and Quirks', '## Driving in Wyoming: What Makes It Different

Wyoming has the lowest population of any U.S. state and some of the longest, emptiest highways in the country. The rules of the road are similar to other states, but the **environment** is dramatically different from the urban driving most national driver-ed materials describe. This lesson covers the laws, hazards, and habits that are specific — or especially important — in Wyoming.

### High Speed Limits and Long Distances

Wyoming has some of the highest posted speed limits in the U.S. Rural sections of **Interstate 80 and Interstate 25** are posted at **80 mph**. Two-lane U.S. highways are often posted at 65 or 70 mph. These limits assume dry pavement, daylight, and full alertness. They are *not* a target speed in rain, snow, wind, or at night.

**Wyoming''s Basic Speed Law** requires every driver to travel at a speed that is reasonable and prudent for current conditions — regardless of the posted limit. A driver doing 80 mph on icy I-80 can be cited even though they are at the speed limit. Conversely, an officer can cite a driver going 25 mph on a clear, empty interstate for impeding traffic.

Distances between towns and services are long. It is normal to drive **100 miles between gas stations** in central and northern Wyoming. Always start trips with at least a half tank of fuel, water, and a charged phone — but understand that cellular coverage is **absent across large swaths of the state**, including most of the Red Desert, the Bighorn Basin, and large portions of US-287, WY-789, and WY-130 (Snowy Range).

### Winter Driving and Road Closures

Wyoming winters are severe. The dominant hazards are:

- **Black ice** on bridges and shaded curves
- **Blowing and drifting snow** that creates whiteouts even on sunny days, particularly on I-80 between Laramie and Rawlins and on US-287 over the Snowy Range
- **High crosswinds**, especially on I-80, which routinely overturn high-profile vehicles (semis, campers, empty pickups with toppers)
- **Wind-driven road closures** — WYDOT regularly closes I-80 to **"light, high-profile vehicles"** (LHPV) when sustained winds exceed about 55 mph

Before any winter trip — and many shoulder-season trips — check **wyoroad.info** or call **511** for current road conditions, closures, and traffic restrictions. "Closed" in Wyoming means closed: gates physically swing across the on-ramps, and driving around them is a misdemeanor that can result in arrest, vehicle impoundment, and fines exceeding $750.

### Wildlife on the Road

Wyoming has one of the highest rates of animal-vehicle collisions in the United States. **Mule deer, white-tailed deer, pronghorn antelope, elk, and moose** all cross highways routinely, and cattle on open range can wander onto unfenced roads in many counties (look for the diamond-shaped **OPEN RANGE** signs).

Wildlife crash risk is highest at **dawn, dusk, and the first few hours after dark**, and peaks during the fall rut (October-November) and spring migration. If you see one animal at the side of the road, expect a second and a third — deer and antelope travel in groups. Do not swerve hard to avoid a single animal: most fatal wildlife-related crashes happen when the driver loses control trying to dodge, not from the impact itself. Brake firmly in a straight line.

### Cell Phones and Distracted Driving

Wyoming bans **texting while driving** statewide for all drivers. Some Wyoming cities — including **Cheyenne, Laramie, Jackson, and Evanston** — have stricter local ordinances that ban *any* handheld cell phone use. As a teen driver in Wyoming you should treat your phone as a no-touch device whenever the car is in gear, regardless of which town you''re in.

### Open Range, Cattle Guards, and Unpaved Roads

Much of rural Wyoming is **open range**, meaning livestock are not fenced off the road. If you hit a cow on an open-range highway, you may be financially liable for the animal. Slow down and watch for cattle guards (metal grates across the road) and stock crossings.

Many Wyoming addresses are reached by **gravel or dirt county roads**. These roads have different physics: shorter stopping distances, easier loss of traction in curves, and significant dust trails that can blind oncoming drivers. Slow down, increase following distance, and lower your headlights to low beam when meeting another vehicle in dust.

### Move Over, Slow Down

Wyoming''s **Move Over Law** requires drivers to change lanes away from — or significantly slow down for — any stopped emergency vehicle, tow truck, or WYDOT maintenance vehicle with flashing lights. Wyoming has lost troopers and plow operators to drivers who failed to move over. On a two-lane road where you cannot change lanes, slow to a speed safe for conditions and pass with as much space as you can give.', 35, 2
);
INSERT OR REPLACE INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_wy_wyoming-specific-rules-and-quirks', 'lesson_wy_wyoming-specific-rules-and-quirks', 'Wyoming-Specific Rules Quiz', 80, 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-specific-rules-and-quirks_0', 'quiz_wy_wyoming-specific-rules-and-quirks', 'What is the maximum posted speed limit on rural sections of Wyoming''s interstates?', '["65 mph","70 mph","75 mph","80 mph"]', 3, 'Rural sections of I-80 and I-25 in Wyoming are posted at 80 mph — among the highest in the U.S. The Basic Speed Law still requires drivers to slow for actual conditions.', 0
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-specific-rules-and-quirks_1', 'quiz_wy_wyoming-specific-rules-and-quirks', 'What does WYDOT mean when it closes I-80 to "light, high-profile vehicles" (LHPV)?', '["Only commercial trucks may use the road","Light, tall vehicles such as empty pickups, campers, and trailers are prohibited due to high winds","Only vehicles with chains may use the road","Only emergency vehicles may use the road"]', 1, 'LHPV closures keep light, tall vehicles off I-80 during high winds because they are most likely to be blown over. Cars and loaded trucks may still travel.', 1
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-specific-rules-and-quirks_2', 'quiz_wy_wyoming-specific-rules-and-quirks', 'You see a single mule deer cross the highway in front of you at dusk. What is the safest reaction?', '["Swerve sharply to the opposite shoulder","Speed up to outrun any others","Brake firmly in a straight line and watch for additional deer","Honk and continue at the same speed"]', 2, 'Deer travel in groups, so expect more. Most fatal wildlife crashes happen from losing control while swerving — brake firmly in a straight line.', 2
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-specific-rules-and-quirks_3', 'quiz_wy_wyoming-specific-rules-and-quirks', 'Which best describes Wyoming''s statewide cell phone law for drivers?', '["All cell phone use is banned for all drivers statewide","Texting while driving is banned for all drivers statewide; some cities also ban handheld use","Only drivers under 18 are restricted","There are no statewide cell phone restrictions"]', 1, 'Wyoming bans texting while driving statewide. Cities like Cheyenne, Laramie, Jackson, and Evanston have stricter local ordinances banning handheld use.', 3
);
INSERT OR REPLACE INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_wy_wyoming-specific-rules-and-quirks_4', 'quiz_wy_wyoming-specific-rules-and-quirks', 'You see a diamond-shaped "OPEN RANGE" sign on a Wyoming highway. What does it mean?', '["The road is open during winter months","Hunting is permitted along the road","Livestock may be on the road and are not required to be fenced off","The shoulder is wide enough for emergency parking"]', 2, 'Open range means cattle and other livestock may wander onto the road. Drivers should slow down, watch for animals, and understand they may be liable for animals they hit.', 4
);

